INSERT INTO lms_modules (id, title, description, tier, related_qa, related_element_codes, duration_minutes, category, renewal_frequency, status) VALUES

-- TIER 1 - MANDATORY (12 modules)
('a0000001-0000-4000-8000-000000000000', 'First Aid in Education & Care (HLTAID012)', 'Nationally accredited first aid training covering emergency response, injury management, and life-threatening situations in education and care settings. Aligns with ACECQA requirements for all educators.', 'mandatory', '{2}', '{2.1.2,2.2.2}', 60, 'first_aid', 'triennial', 'published'),
('a0000002-0000-4000-8000-000000000000', 'CPR Refresher (HLTAID009)', 'Annual cardiopulmonary resuscitation refresher to maintain current CPR competency as required under the Education and Care Services National Regulations.', 'mandatory', '{2}', '{2.1.2,2.2.2}', 30, 'first_aid', 'annual', 'published'),
('a0000003-0000-4000-8000-000000000000', 'Anaphylaxis Management', 'Training in recognising and responding to anaphylactic reactions in children, including the administration of adrenaline auto-injectors and development of risk minimisation plans.', 'mandatory', '{2}', '{2.1.2}', 20, 'first_aid', 'annual', 'published'),
('a0000004-0000-4000-8000-000000000000', 'Emergency Asthma Management', 'Evidence-based training on asthma first aid, recognition of acute episodes, use of reliever medication, and development of asthma management plans in ECEC settings.', 'mandatory', '{2}', '{2.1.2}', 20, 'first_aid', 'annual', 'published'),
('a0000005-0000-4000-8000-000000000000', 'ACECQA Foundations of Child Safety', 'Foundational module developed in alignment with the ACECQA child safe framework, covering organisational culture, risk identification, and child-centred approaches to safety.', 'mandatory', '{2,7}', '{2.2.3,7.1.2}', 45, 'child_safety', 'once', 'published'),
('a0000006-0000-4000-8000-000000000000', 'ACECQA Advanced Child Safety', 'Advanced exploration of child safe standards, including governance accountability, complaint handling processes, and embedding child safety into quality improvement processes.', 'mandatory', '{2,7}', '{2.2.3,7.1.2}', 60, 'child_safety', 'once', 'published'),
('a0000007-0000-4000-8000-000000000000', 'Child Protection & Mandatory Reporting', 'Legal obligations for mandatory reporters in ECEC, including recognising indicators of abuse and neglect, reporting procedures, and documentation requirements under state and territory legislation.', 'mandatory', '{2}', '{2.2.3}', 30, 'child_safety', 'annual', 'published'),
('a0000008-0000-4000-8000-000000000000', 'Working with Children Check Obligations', 'Understanding the requirements for Working with Children Checks, including application processes, renewal timelines, and the obligations of both individuals and approved providers.', 'mandatory', '{2,4}', '{4.2.2}', 15, 'compliance', 'once', 'published'),
('a0000009-0000-4000-8000-000000000000', 'Food Safety & Hygiene', 'Food handling, preparation, and storage practices in ECEC settings, including allergen management, infection control, and compliance with food safety standards and regulations.', 'mandatory', '{2}', '{2.1.3,2.1.2}', 30, 'health_hygiene', 'triennial', 'published'),
('a0000010-0000-4000-8000-000000000000', 'WHS Induction for ECEC', 'Work health and safety fundamentals for early childhood educators, including hazard identification, risk assessment, incident reporting, and duty of care obligations.', 'mandatory', '{2,3}', '{3.1.2}', 30, 'whs', 'annual', 'published'),
('a0000011-0000-4000-8000-000000000000', 'Safe Sleep & Rest Practices', 'Evidence-based safe sleep and rest practices aligned with Red Nose Australia guidelines and National Regulations, including SIDS risk reduction, supervision during rest, and individual sleep plans.', 'mandatory', '{2}', '{2.1.1}', 25, 'health_hygiene', 'annual', 'published'),
('a0000012-0000-4000-8000-000000000000', 'Emergency Evacuation & Lockdown', 'Planning and conducting emergency evacuations and lockdown procedures in ECEC settings, including regulatory requirements for rehearsal frequency, documentation, and communication with families.', 'mandatory', '{2}', '{2.2.2}', 20, 'whs', 'annual', 'published'),

-- TIER 2 - CORE (14 modules)
('a0000013-0000-4000-8000-000000000000', 'Understanding NQF, NQS & National Regulations', 'Overview of the National Quality Framework, the seven Quality Areas of the National Quality Standard, and key provisions of the Education and Care Services National Regulations.', 'core', '{7}', '{7.1.2}', 30, 'compliance', NULL, 'published'),
('a0000014-0000-4000-8000-000000000000', 'EYLF V2.0 Framework Essentials', 'Exploring the principles, practices, and learning outcomes of Belonging, Being and Becoming: The Early Years Learning Framework for Australia (V2.0) and its application to programming.', 'core', '{1}', '{1.1.1}', 40, 'curriculum', NULL, 'published'),
('a0000015-0000-4000-8000-000000000000', 'The Planning Cycle', 'Understanding the observe-analyse-plan-implement-evaluate cycle and its role in responsive, child-centred curriculum planning that meets each child''s learning needs.', 'core', '{1}', '{1.3.1,1.3.2}', 35, 'curriculum', NULL, 'published'),
('a0000016-0000-4000-8000-000000000000', 'Intentional Teaching Strategies', 'Deliberate, purposeful, and thoughtful teaching practices that extend children''s thinking and learning, including scaffolding, modelling, open questioning, and co-construction.', 'core', '{1}', '{1.2.1}', 30, 'curriculum', NULL, 'published'),
('a0000017-0000-4000-8000-000000000000', 'Documenting Children''s Learning', 'Effective pedagogical documentation methods including learning stories, portfolios, and formative assessment that make children''s learning visible and inform the planning cycle.', 'core', '{1}', '{1.3.1,1.3.3}', 30, 'curriculum', NULL, 'published'),
('a0000018-0000-4000-8000-000000000000', 'Positive Behaviour Guidance', 'Evidence-based strategies for supporting positive behaviour in young children, including setting clear expectations, natural consequences, and building prosocial skills.', 'core', '{5}', '{5.1.1,5.2.2}', 30, 'behaviour', NULL, 'published'),
('a0000019-0000-4000-8000-000000000000', 'Supporting Self-Regulation', 'Understanding the development of self-regulation in young children and practical strategies to support emotional literacy, impulse control, and executive function skills.', 'core', '{5}', '{5.2.2}', 25, 'behaviour', NULL, 'published'),
('a0000020-0000-4000-8000-000000000000', 'Building Partnerships with Families', 'Strategies for establishing respectful, collaborative partnerships with families that recognise them as children''s first and most influential educators.', 'core', '{6}', '{6.1.1,6.1.2}', 25, 'families', NULL, 'published'),
('a0000021-0000-4000-8000-000000000000', 'Inclusive Practice & Additional Needs', 'Creating inclusive environments that respect diversity and support the participation and learning of all children, including those with additional needs and developmental delays.', 'core', '{3,5,6}', '{3.2.1,5.1.2,6.2.2}', 35, 'inclusion', NULL, 'published'),
('a0000022-0000-4000-8000-000000000000', 'Cultural Competency Foundations', 'Developing cultural awareness, knowledge, and skills to work respectfully and effectively with children and families from diverse cultural and linguistic backgrounds.', 'core', '{1,5,6}', '{1.1.2,5.1.2,6.2.2}', 30, 'inclusion', NULL, 'published'),
('a0000023-0000-4000-8000-000000000000', 'Active Supervision Strategies', 'Effective supervision practices including positioning, scanning, listening, anticipating, and engaging to ensure children''s safety while supporting play and learning.', 'core', '{2}', '{2.2.1}', 20, 'health_hygiene', NULL, 'published'),
('a0000024-0000-4000-8000-000000000000', 'Quality Improvement Planning (QIP)', 'Understanding the purpose and structure of the Quality Improvement Plan, how to identify strengths and areas for improvement, and engage the whole team in continuous improvement.', 'core', '{7}', '{7.2.1}', 30, 'leadership', NULL, 'published'),
('a0000025-0000-4000-8000-000000000000', 'ECA Code of Ethics & Professional Standards', 'Exploring the Early Childhood Australia Code of Ethics, professional standards for educators, and how ethical practice underpins quality outcomes for children.', 'core', '{4}', '{4.2.2}', 25, 'professional', NULL, 'published'),
('a0000026-0000-4000-8000-000000000000', 'Service Induction', 'Comprehensive orientation to service policies, procedures, philosophy, routines, and expectations for new team members joining the education and care team.', 'core', '{4,7}', '{4.1.2,7.1.3}', 45, 'professional', NULL, 'published'),

-- TIER 3 - ADVANCED (15 modules)
('a0000027-0000-4000-8000-000000000000', 'Critical Reflection for Educators', 'Developing skills in critical reflection to examine assumptions, challenge practice, and use theory to inform decision-making and continuous professional growth.', 'advanced', '{1,7}', '{1.3.2,7.2.1}', 30, 'professional', NULL, 'published'),
('a0000028-0000-4000-8000-000000000000', 'Aboriginal & Torres Strait Islander Perspectives', 'Embedding Aboriginal and Torres Strait Islander perspectives, histories, and cultures into curriculum and practice, and building genuine relationships with First Nations communities.', 'advanced', '{1,5,6}', '{1.1.2,6.2.2}', 35, 'inclusion', NULL, 'published'),
('a0000029-0000-4000-8000-000000000000', 'Trauma-Informed Practice in Early Childhood', 'Understanding the impact of trauma on young children''s development and behaviour, and implementing trauma-sensitive approaches that promote healing, safety, and trust.', 'advanced', '{2,5}', '{5.1.1,5.2.2}', 35, 'behaviour', NULL, 'published'),
('a0000030-0000-4000-8000-000000000000', 'Sustained Shared Thinking & Deep Learning', 'Exploring sustained shared thinking as a pedagogical approach to extend children''s thinking, support deep-level learning, and build intellectual dispositions.', 'advanced', '{1,5}', '{1.2.2,5.2.1}', 30, 'curriculum', NULL, 'published'),
('a0000031-0000-4000-8000-000000000000', 'Educational Leadership in Practice', 'The role and responsibilities of educational leaders in driving curriculum quality, mentoring educators, and leading collaborative approaches to pedagogy and practice.', 'advanced', '{7}', '{7.2.2}', 30, 'leadership', NULL, 'published'),
('a0000032-0000-4000-8000-000000000000', 'Environmental Sustainability with Children', 'Embedding sustainability practices into daily routines and curriculum, fostering children''s connection to the natural world, and promoting environmental stewardship.', 'advanced', '{3}', '{3.2.3}', 25, 'environment', NULL, 'published'),
('a0000033-0000-4000-8000-000000000000', 'Supporting Transitions', 'Strategies for supporting children and families through key transitions including home to service, room to room, and service to school, with sensitivity to individual needs.', 'advanced', '{6}', '{6.2.1}', 25, 'families', NULL, 'published'),
('a0000034-0000-4000-8000-000000000000', 'Engaging Families in Programming & Assessment', 'Meaningful strategies for involving families in curriculum decision-making, sharing documentation, and valuing family input in children''s learning and assessment.', 'advanced', '{1,6}', '{1.3.3,6.1.1}', 25, 'families', NULL, 'published'),
('a0000035-0000-4000-8000-000000000000', 'Community Partnerships & Referral Pathways', 'Building and maintaining partnerships with community organisations, allied health professionals, and support agencies to enhance outcomes for children and families.', 'advanced', '{6}', '{6.2.3}', 25, 'families', NULL, 'published'),
('a0000036-0000-4000-8000-000000000000', 'Mentoring & Coaching Skills for Leaders', 'Practical mentoring and coaching skills for educational leaders, room leaders, and experienced educators to support the professional growth of colleagues.', 'advanced', '{4,7}', '{4.2.1,7.2.3}', 30, 'leadership', NULL, 'published'),
('a0000037-0000-4000-8000-000000000000', 'Risk-Benefit Assessment in Play Environments', 'Balancing safety with challenge in play environments through risk-benefit assessment, supporting children''s risk competence, and designing stimulating outdoor spaces.', 'advanced', '{2,3}', '{2.2.1,3.2.2}', 25, 'environment', NULL, 'published'),
('a0000038-0000-4000-8000-000000000000', 'Children''s Rights, Agency & Participation', 'Exploring children''s rights under the UNCRC, supporting children''s agency and voice in decision-making, and embedding participatory practices in daily routines.', 'advanced', '{5}', '{5.1.2}', 25, 'behaviour', NULL, 'published'),
('a0000039-0000-4000-8000-000000000000', 'Leading Change & Continuous Improvement', 'Frameworks and strategies for leading change in ECEC settings, building team capacity, managing resistance, and sustaining momentum for continuous quality improvement.', 'advanced', '{7}', '{7.2.1}', 30, 'leadership', NULL, 'published'),
('a0000040-0000-4000-8000-000000000000', 'Philosophy Development & Review', 'Guiding teams through collaborative development and review of a service philosophy that reflects values, beliefs, and aspirations for children, families, and community.', 'advanced', '{7}', '{7.1.1}', 25, 'leadership', NULL, 'published'),
('a0000041-0000-4000-8000-000000000000', 'Performance Review & PDP Development', 'Conducting effective performance reviews and developing Professional Development Plans that align individual growth goals with service quality improvement priorities.', 'advanced', '{4,7}', '{7.2.3,4.2.1}', 30, 'professional', NULL, 'published');


-- ============================================
-- 2. MODULE SECTIONS (4 per module = 164 total)
-- ============================================

INSERT INTO lms_module_sections (id, module_id, sort_order, section_type, title, content, estimated_minutes) VALUES

-- Module 1: First Aid in Education & Care (HLTAID012)
('b0000001-0000-4000-8000-000000000000', 'a0000001-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'First aid competency is a legal requirement for all educators working in education and care settings under the National Regulations. This module covers the essential skills needed to provide immediate and effective first aid response to children and colleagues. Maintaining current first aid qualifications demonstrates your commitment to children''s safety and wellbeing.', 15),
('b0000002-0000-4000-8000-000000000000', 'a0000001-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Under Regulation 136, at least one educator with a current approved first aid qualification must be in attendance at all times children are being educated and cared for. The DRSABCD action plan (Danger, Response, Send for help, Airway, Breathing, CPR, Defibrillation) is the foundation of emergency response. Educators must be able to manage common childhood injuries including bumps, cuts, fractures, burns, bites, and allergic reactions. Accurate incident documentation using your service''s incident, injury, trauma and illness record is essential for compliance with Regulation 87. First aid kits must be readily accessible, regularly checked, and stocked according to the contents list specified in your service policies. Educators should practise a calm, reassuring approach when providing first aid to minimise distress for the injured child and other children present.', 30),
('b0000003-0000-4000-8000-000000000000', 'a0000001-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 10),
('b0000004-0000-4000-8000-000000000000', 'a0000001-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about the last time you responded to an injury or illness at your service. What went well and what could be improved in your response process?', 5),

-- Module 2: CPR Refresher (HLTAID009)
('b0000005-0000-4000-8000-000000000000', 'a0000002-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'CPR is a life-saving skill that must be practised regularly to maintain competency. Under Regulation 137, at least one person with current approved CPR training must be present at the service at all times. This annual refresher ensures your skills remain current and effective.', 8),
('b0000006-0000-4000-8000-000000000000', 'a0000002-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The compression-to-breath ratio for infant CPR (under 1 year) is 30:2 using two fingers for compressions at a depth of approximately one-third of the chest depth. For children aged 1-8 years, use the heel of one hand for compressions at a depth of approximately one-third of the chest depth, maintaining the 30:2 ratio. Compressions should be delivered at a rate of 100-120 per minute, allowing full chest recoil between compressions. An AED can be used on children of any age; use paediatric pads if available, otherwise use adult pads ensuring they do not touch or overlap. Early recognition of cardiac arrest, early CPR, and early defibrillation are the critical links in the chain of survival. Always call 000 (or instruct someone to call) before commencing CPR, and continue until medical help arrives or the casualty shows signs of life.', 15),
('b0000007-0000-4000-8000-000000000000', 'a0000002-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000008-0000-4000-8000-000000000000', 'a0000002-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Consider your confidence level in performing CPR on an infant versus a child. What specific aspects of CPR would you like to practise more during your next face-to-face refresher?', 2),

-- Module 3: Anaphylaxis Management
('b0000009-0000-4000-8000-000000000000', 'a0000003-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Anaphylaxis is a severe, potentially life-threatening allergic reaction that requires immediate treatment. In ECEC settings, educators may be the first responders when a child experiences anaphylaxis. Understanding how to recognise symptoms and administer an adrenaline auto-injector can save a child''s life.', 5),
('b0000010-0000-4000-8000-000000000000', 'a0000003-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Common triggers for anaphylaxis in children include nuts, eggs, cow''s milk, shellfish, insect stings, and certain medications. Signs of anaphylaxis include difficulty breathing, swelling of the tongue and throat, hoarse voice, wheeze or persistent cough, dizziness or collapse, and paleness and floppiness in young children. Adrenaline auto-injectors (EpiPen) come in two doses: EpiPen Jr (0.15mg) for children 7.5-20kg and EpiPen (0.3mg) for those over 20kg. Always administer the adrenaline auto-injector first, then call 000 for an ambulance. Each child at risk must have an ASCIA Action Plan for Anaphylaxis that is current, displayed, and accessible to all educators. Risk minimisation plans should address food management, cross-contamination prevention, and communication with families about allergen exposure.', 10),
('b0000011-0000-4000-8000-000000000000', 'a0000003-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 3),
('b0000012-0000-4000-8000-000000000000', 'a0000003-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Can you locate every child''s medical management plan in your room right now? Reflect on how your team communicates about children with allergies during handovers and relief staffing.', 2),

-- Module 4: Emergency Asthma Management
('b0000013-0000-4000-8000-000000000000', 'a0000004-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Asthma is one of the most common chronic conditions in Australian children, affecting approximately one in nine children. Educators must be confident in recognising asthma symptoms and providing asthma first aid. Prompt and correct action during an asthma emergency can prevent a life-threatening situation.', 5),
('b0000014-0000-4000-8000-000000000000', 'a0000004-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The 4x4x4 asthma first aid protocol involves: sit the child upright and stay calm, give 4 puffs of blue reliever (Ventolin/salbutamol) via a spacer, wait 4 minutes, and if no improvement give 4 more puffs, repeating until the ambulance arrives. Common asthma triggers include respiratory infections, exercise, cold air, dust, pollen, smoke, and strong emotions. Warning signs of a severe asthma attack include little or no improvement after using reliever, inability to speak in full sentences, lips turning blue, and increasing distress. Each child with asthma must have a current Asthma Action Plan completed by their doctor, which should be reviewed annually and updated after any hospital visit. Reliever medication and spacers should be readily accessible, labelled with the child''s name, and checked for expiry regularly. Educators should also be aware of the service''s emergency asthma kit containing a blue reliever puffer and spacer for general emergency use.', 10),
('b0000015-0000-4000-8000-000000000000', 'a0000004-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 3),
('b0000016-0000-4000-8000-000000000000', 'a0000004-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Review the asthma management plans in your room. Are you confident you could locate and administer reliever medication for each child with asthma in an emergency?', 2),

-- Module 5: ACECQA Foundations of Child Safety
('b0000017-0000-4000-8000-000000000000', 'a0000005-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'The National Principles for Child Safe Organisations provide the foundation for creating environments where children are safe, informed, and participate in decisions that affect them. ACECQA''s child safe framework supports services to embed child safety into every aspect of their operations. This module builds foundational understanding of what it means to be a genuinely child safe service.', 10),
('b0000018-0000-4000-8000-000000000000', 'a0000005-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The National Principles for Child Safe Organisations include ten principles that address leadership, child participation, family engagement, equity, safe environments, and continuous improvement. A child safe culture requires that child safety is embedded in leadership, governance, and organisational culture, not treated as a standalone policy. Children''s participation is central to child safety: services must create safe ways for children to express their views, concerns, and ideas about their safety and wellbeing. All adults in the service have a shared responsibility for child safety, including educators, volunteers, students, contractors, and family members. Risk management for child safety goes beyond physical hazards to include online safety, inappropriate behaviour, grooming, and situations where children may be vulnerable. Regular review and improvement of child safety practices should be included in the Quality Improvement Plan and discussed at team meetings.', 25),
('b0000019-0000-4000-8000-000000000000', 'a0000005-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000020-0000-4000-8000-000000000000', 'a0000005-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'How does your service currently empower children to speak up about their safety? What is one practice you could implement to strengthen children''s voice in child safety?', 5),

-- Module 6: ACECQA Advanced Child Safety
('b0000021-0000-4000-8000-000000000000', 'a0000006-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Building on foundational child safety knowledge, this advanced module explores how governance structures, complaint handling, and organisational accountability work together to protect children. Genuine child safety requires systemic approaches, not just individual awareness. This module supports educators and leaders to drive child safe culture at every level.', 15),
('b0000022-0000-4000-8000-000000000000', 'a0000006-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Governance accountability for child safety means that approved providers and persons with management or control must actively lead child safe practices, not merely delegate responsibility. Robust complaint handling procedures should be accessible, transparent, and responsive, with clear pathways for children, families, and staff to raise concerns without fear of reprisal. Recordkeeping for child safety must be thorough, confidential, and maintained in accordance with privacy legislation and regulatory requirements. Services should conduct regular child safety audits that examine physical environments, staffing practices, supervision protocols, and organisational culture. Embedding child safety into the QIP ensures that strategies are documented, assigned, monitored, and reviewed as part of the continuous improvement cycle. Cultural safety is integral to child safety, particularly for Aboriginal and Torres Strait Islander children and children from culturally and linguistically diverse backgrounds.', 30),
('b0000023-0000-4000-8000-000000000000', 'a0000006-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 10),
('b0000024-0000-4000-8000-000000000000', 'a0000006-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'When was the last time your service reviewed its complaint handling procedures? Consider whether families and staff feel genuinely safe to raise concerns.', 5),

-- Module 7: Child Protection & Mandatory Reporting
('b0000025-0000-4000-8000-000000000000', 'a0000007-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Educators in ECEC are mandatory reporters with a legal obligation to report concerns about children at risk of significant harm. This responsibility exists regardless of the source of harm and applies to all educators, not just those in leadership roles. Understanding your obligations ensures vulnerable children receive the protection they need.', 8),
('b0000026-0000-4000-8000-000000000000', 'a0000007-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Mandatory reporters must report to the relevant child protection authority when they have reasonable grounds to suspect a child is at risk of significant harm from abuse or neglect. The four types of child abuse are physical abuse, emotional or psychological abuse, sexual abuse, and neglect, and each may present with different indicators. Behavioural indicators may include withdrawal, regression, aggression, fear of certain adults, age-inappropriate sexual behaviour, or reluctance to go home. Physical indicators may include unexplained bruising in unusual locations, burns, fractures, poor hygiene, malnutrition, or inappropriate clothing for weather conditions. You do not need proof to make a report; a reasonable suspicion based on your professional observations is sufficient. Reports are made to your state or territory child protection authority, and the reporter''s identity is protected by law; it is an offence to disclose the identity of a reporter.', 15),
('b0000027-0000-4000-8000-000000000000', 'a0000007-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000028-0000-4000-8000-000000000000', 'a0000007-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Do you feel confident in the process for making a mandatory report at your service? Reflect on any barriers that might prevent you or a colleague from reporting a concern.', 2),

-- Module 8: Working with Children Check Obligations
('b0000029-0000-4000-8000-000000000000', 'a0000008-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Working with Children Checks (WWCC) are a mandatory requirement for anyone who works or volunteers with children in education and care settings. These checks are a critical safeguard, screening individuals for criminal history that may pose a risk to children. Understanding your obligations ensures compliance and protects children in your care.', 4),
('b0000030-0000-4000-8000-000000000000', 'a0000008-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'All staff, volunteers, and students on placement must hold a valid WWCC (or equivalent) for the state or territory in which they work before commencing in a child-related role. The approved provider has a legal obligation to verify the WWCC status of every person engaged in child-related work and maintain records of these checks. WWCC requirements vary by state and territory; for example, NSW uses the WWCC, Victoria uses the WWVP Check, and Queensland uses the Blue Card. Checks must be renewed before expiry, and any changes to criminal history may trigger a reassessment or revocation of clearance. If a person''s WWCC is revoked, cancelled, or suspended, they must immediately cease working with children and the approved provider must be notified. The WWCC does not replace other suitability assessments; services should also conduct reference checks, interviews, and ongoing supervision.', 8),
('b0000031-0000-4000-8000-000000000000', 'a0000008-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 2),
('b0000032-0000-4000-8000-000000000000', 'a0000008-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Check the expiry date of your own WWCC right now. Does your service have a system in place to track and remind staff about upcoming renewals?', 1),

-- Module 9: Food Safety & Hygiene
('b0000033-0000-4000-8000-000000000000', 'a0000009-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Safe food handling is essential in ECEC settings where children are particularly vulnerable to foodborne illness. Regulation 77-80 set out requirements for food and beverages including nutrition, allergen management, and safe preparation. Educators involved in food preparation, serving, or supervision must understand and follow food safety practices.', 8),
('b0000034-0000-4000-8000-000000000000', 'a0000009-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The temperature danger zone for food is between 5 degrees and 60 degrees Celsius; perishable food should not remain in this zone for more than two hours total. Hand hygiene is the single most important practice in preventing the spread of infection; hands must be washed before and after handling food, after toileting, and after contact with body fluids. Cross-contamination between raw and cooked foods must be prevented through separate chopping boards, utensils, and storage areas. Allergen management requires clear labelling of all foods, checking ingredient lists, communicating with families, and ensuring individual dietary requirements are displayed and followed. Bottle preparation for infants must follow strict hygiene procedures including sterilisation, correct formula mixing, temperature checking, and individual labelling. All food must be stored correctly: refrigerated items below 5 degrees, frozen items below minus 15 degrees, and dry goods in sealed containers off the floor.', 15),
('b0000035-0000-4000-8000-000000000000', 'a0000009-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000036-0000-4000-8000-000000000000', 'a0000009-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Walk through your service''s food preparation area. Are chopping boards colour-coded, foods labelled with dates, and allergen information clearly displayed?', 2),

-- Module 10: WHS Induction for ECEC
('b0000037-0000-4000-8000-000000000000', 'a0000010-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Work Health and Safety (WHS) legislation requires all workplaces, including ECEC services, to provide a safe environment for workers, children, and visitors. Every educator has both rights and responsibilities under WHS law. This induction ensures you understand your obligations and can contribute to a safe workplace from day one.', 8),
('b0000038-0000-4000-8000-000000000000', 'a0000010-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Under WHS legislation, the Person Conducting a Business or Undertaking (PCBU), which includes approved providers, has the primary duty to ensure the health and safety of workers and others at the workplace. Workers have a duty to take reasonable care for their own health and safety, cooperate with reasonable policies and procedures, and not adversely affect the health and safety of others. Hazard identification should be ongoing and systematic: conduct daily safety checks of indoor and outdoor environments, equipment, and materials before children arrive. The risk management process involves identifying hazards, assessing the risk, implementing control measures, and reviewing effectiveness. All incidents, injuries, and near misses must be reported and documented using your service''s incident reporting system, and notifiable incidents must be reported to the WHS regulator. Manual handling risks in ECEC are significant; use correct lifting techniques when handling children, equipment, and furniture, and report any musculoskeletal discomfort early.', 15),
('b0000039-0000-4000-8000-000000000000', 'a0000010-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000040-0000-4000-8000-000000000000', 'a0000010-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about the last week at your service. Were there any hazards you noticed but did not report? What prevented you from taking action?', 2),

-- Module 11: Safe Sleep & Rest Practices
('b0000041-0000-4000-8000-000000000000', 'a0000011-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Safe sleep practices in ECEC settings are critical for reducing the risk of Sudden Infant Death Syndrome (SIDS) and fatal sleeping accidents. Regulation 81 requires services to ensure each child has appropriate opportunities for sleep, rest, and relaxation. Every educator must understand and consistently implement safe sleep guidelines.', 7),
('b0000042-0000-4000-8000-000000000000', 'a0000011-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Red Nose Australia''s six safe sleeping recommendations are: sleep baby on their back, keep head and face uncovered, keep baby smoke-free before and after birth, safe sleeping environment (safe cot, safe mattress, safe bedding), sleep baby in their own safe space in the same room as caregiver, and breastfeed baby. Educators must conduct regular sleep checks at intervals documented in the service policy, typically every 10-15 minutes, observing the child''s breathing, colour, and temperature. Each child should have an individual sleep and rest plan developed in consultation with families that respects cultural practices while maintaining safe sleep requirements. The sleep environment must be well-ventilated, maintain a comfortable temperature, have adequate lighting for supervision, and be free from loose bedding, pillows, bumpers, and soft toys for infants. Children should never be forced to sleep; the focus should be on providing restful, calming environments where children can choose to rest without pressure. Documentation of sleep and rest practices, including check times and observations, must be maintained and available for families and regulators.', 12),
('b0000043-0000-4000-8000-000000000000', 'a0000011-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000044-0000-4000-8000-000000000000', 'a0000011-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Review your room''s sleep checking procedures. Are checks being conducted and documented at the required intervals? Are all staff in your room consistent in their approach?', 2),

-- Module 12: Emergency Evacuation & Lockdown
('b0000045-0000-4000-8000-000000000000', 'a0000012-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Emergency evacuations and lockdown procedures must be practised regularly to ensure the safety of all children and staff during critical incidents. Under Regulation 97, services must rehearse emergency and evacuation procedures every three months. Confidence in these procedures can make the difference between a calm, orderly response and a chaotic one.', 5),
('b0000046-0000-4000-8000-000000000000', 'a0000012-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Evacuation procedures must cover scenarios including fire, gas leak, flood, bomb threat, and structural damage, with designated assembly points and evacuation routes clearly marked and accessible. Lockdown procedures are used when there is a threat on or near the premises, such as an intruder, dangerous animal, or nearby police operation; all doors and windows are secured and children are moved away from windows. A current attendance record is essential during any emergency to account for every child and adult; this includes the daily sign-in register, visitor log, and staff roster. Emergency rehearsals must be documented including the date, time, type of emergency practised, number of participants, time taken, and any issues identified for improvement. Educators should practise remaining calm, using simple instructions, and maintaining visual and verbal contact with children during emergencies. After each rehearsal, conduct a debrief with all staff to evaluate effectiveness, identify barriers, and update procedures.', 10),
('b0000047-0000-4000-8000-000000000000', 'a0000012-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 3),
('b0000048-0000-4000-8000-000000000000', 'a0000012-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'When was your last emergency rehearsal? Were there any challenges such as children who were distressed, or routes that were blocked? How were these addressed?', 2),

-- Module 13: Understanding NQF, NQS & National Regulations
('b0000049-0000-4000-8000-000000000000', 'a0000013-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'The National Quality Framework (NQF) sets the benchmark for quality in Australian education and care services. Understanding the NQS and National Regulations is fundamental to your role as an educator. This knowledge empowers you to contribute meaningfully to quality improvement at your service.', 8),
('b0000050-0000-4000-8000-000000000000', 'a0000013-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The NQF comprises the National Law, National Regulations, the National Quality Standard, the assessment and rating process, and approved learning frameworks (EYLF and MTOP). The NQS contains seven Quality Areas: QA1 Educational Program and Practice, QA2 Children''s Health and Safety, QA3 Physical Environment, QA4 Staffing Arrangements, QA5 Relationships with Children, QA6 Collaborative Partnerships, and QA7 Governance and Leadership. Services are rated against each Quality Area and receive an overall rating of Significant Improvement Required, Working Towards, Meeting, Exceeding, or Excellent. To achieve an Exceeding rating, services must demonstrate practice that is embedded, informed by critical reflection, and shaped by meaningful engagement with families and community. The National Regulations set out operational requirements including staffing qualifications, educator-to-child ratios, documentation, and physical environment standards. Every educator should be familiar with the QIP and understand how their daily practice contributes to meeting and exceeding the NQS.', 15),
('b0000051-0000-4000-8000-000000000000', 'a0000013-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000052-0000-4000-8000-000000000000', 'a0000013-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Which Quality Area do you feel most confident about in your daily practice? Which one would you like to learn more about, and why?', 2),

-- Module 14: EYLF V2.0 Framework Essentials
('b0000053-0000-4000-8000-000000000000', 'a0000014-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Belonging, Being and Becoming: The Early Years Learning Framework V2.0 is the approved national learning framework for children from birth to five years. It guides educators in developing quality programs that support each child''s learning and development. Understanding the EYLF is essential for all educators delivering programs under the NQF.', 10),
('b0000054-0000-4000-8000-000000000000', 'a0000014-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The EYLF V2.0 is built on the vision that all children experience learning that is engaging and builds success for life, and is underpinned by the concepts of Belonging, Being, and Becoming. The eight practices of the EYLF V2.0 include adopting holistic approaches, being responsive to children, planning and implementing learning through play, intentional teaching, creating physical and social learning environments, valuing cultural and social contexts, providing for continuity and transitions, and assessing and monitoring learning. The five learning outcomes are: children have a strong sense of identity, children are connected with and contribute to their world, children have a strong sense of wellbeing, children are confident and involved learners, and children are effective communicators. The EYLF V2.0 strengthened the focus on Aboriginal and Torres Strait Islander perspectives, sustainability, and critical reflection compared to V1.0. Educators use the EYLF to inform their planning cycle, linking observations and assessments to learning outcomes and using this to plan intentional experiences. The principles of the EYLF, including secure respectful relationships, partnerships, equity and diversity, and ongoing learning and reflective practice, underpin all pedagogical decisions.', 20),
('b0000055-0000-4000-8000-000000000000', 'a0000014-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000056-0000-4000-8000-000000000000', 'a0000014-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Choose one of the five EYLF learning outcomes. How did you support this outcome in your program this week? What evidence could you document?', 5),

-- Module 15: The Planning Cycle
('b0000057-0000-4000-8000-000000000000', 'a0000015-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'The planning cycle is the foundation of responsive, child-centred curriculum in ECEC. It is an ongoing process of observing, analysing, planning, implementing, and evaluating that ensures programs are meaningful and relevant to each child. Effective use of the planning cycle is central to meeting QA1.', 8),
('b0000058-0000-4000-8000-000000000000', 'a0000015-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The planning cycle is a continuous, cyclical process: observe children''s interests, strengths and needs; analyse what you observe using developmental knowledge and the EYLF; plan experiences that extend learning; implement with intentionality; and evaluate the outcomes. Observations should capture children''s learning in multiple contexts including play, routines, and interactions, using a range of methods such as anecdotal records, photographs, work samples, and learning stories. Analysis involves connecting observations to EYLF learning outcomes, considering developmental milestones, and identifying individual learning trajectories. Planning should be responsive and flexible, incorporating children''s voices, family input, and spontaneous learning moments alongside planned experiences. Evaluation requires educators to critically reflect on whether planned experiences achieved their intended purpose and how they can be extended or modified. Documentation of the planning cycle should be visible and accessible, demonstrating the link between observations, analysis, planning, and outcomes for children.', 18),
('b0000059-0000-4000-8000-000000000000', 'a0000015-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000060-0000-4000-8000-000000000000', 'a0000015-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Look at your most recent program plan. Can you trace the pathway from a specific observation through to the planned experience? What step of the cycle is strongest in your practice?', 4),

-- Module 16: Intentional Teaching Strategies
('b0000061-0000-4000-8000-000000000000', 'a0000016-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Intentional teaching involves educators being deliberate, purposeful, and thoughtful in their decisions and actions to support children''s learning. It is not about directing or controlling learning, but about knowing when and how to intervene to extend thinking. The EYLF identifies intentional teaching as a key practice for educators.', 8),
('b0000062-0000-4000-8000-000000000000', 'a0000016-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Intentional teaching sits on a continuum from child-initiated to educator-initiated experiences, and effective educators move fluidly along this continuum depending on the learning context. Scaffolding involves providing temporary support to help children achieve something they cannot yet do independently, then gradually withdrawing support as competence grows. Open-ended questioning encourages higher-order thinking: questions like "What do you think might happen if...?" or "How could we solve this problem?" extend learning beyond recall. Modelling and demonstrating are intentional strategies where educators explicitly show skills, thinking processes, or social behaviours for children to observe and practise. Co-construction of learning occurs when educators and children collaborate as equal partners in exploring ideas, solving problems, and building knowledge together. Effective intentional teaching requires educators to know each child well, draw on knowledge of child development, and make real-time pedagogical decisions based on observation.', 15),
('b0000063-0000-4000-8000-000000000000', 'a0000016-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000064-0000-4000-8000-000000000000', 'a0000016-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about a recent interaction with a child during play. What intentional teaching strategy did you use, or could you have used, to extend their learning in that moment?', 2),

-- Module 17: Documenting Children's Learning
('b0000065-0000-4000-8000-000000000000', 'a0000017-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Pedagogical documentation is more than a record of what happened; it makes children''s learning visible, informs the planning cycle, and communicates with families about their child''s progress. Quality documentation demonstrates the link between your program and children''s learning outcomes. It is a professional responsibility that directly supports QA1.', 8),
('b0000066-0000-4000-8000-000000000000', 'a0000017-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Learning stories are a narrative form of documentation that captures the child''s learning journey, including what happened, the learning that occurred (linked to EYLF outcomes), and planned next steps. Portfolios are collections of documentation that build a picture of each child''s learning over time and should include observations, work samples, photographs, and family contributions. Formative assessment in ECEC is ongoing and embedded in daily practice; it involves gathering evidence of learning to inform planning rather than measuring achievement against benchmarks. Documentation should include the child''s voice: their words, ideas, questions, and theories, captured through dictation, audio recording, or transcription. Families should have ongoing access to their child''s documentation and be invited to contribute observations from home that enrich the picture of the child''s learning. Effective documentation is timely, meaningful, and manageable; it prioritises quality over quantity and focuses on significant learning moments rather than documenting everything.', 15),
('b0000067-0000-4000-8000-000000000000', 'a0000017-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000068-0000-4000-8000-000000000000', 'a0000017-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Review a recent piece of documentation you wrote. Does it include the child''s voice, a link to EYLF outcomes, and a clear next step for learning?', 2),

-- Module 18: Positive Behaviour Guidance
('b0000069-0000-4000-8000-000000000000', 'a0000018-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Positive behaviour guidance focuses on teaching children the skills they need to manage their behaviour, rather than punishing unwanted behaviour. The NQS requires educators to support each child to manage their own behaviour and respond appropriately to the behaviour of others. This approach builds children''s social competence and self-esteem.', 8),
('b0000070-0000-4000-8000-000000000000', 'a0000018-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Behaviour is communication: all behaviour serves a purpose, and understanding what a child is trying to communicate through their behaviour is the first step in providing effective guidance. Preventive strategies are the foundation of positive behaviour guidance: establishing clear, consistent expectations, arranging environments to minimise conflict, and providing engaging programs that reduce boredom. Responsive relationships are key: children are more likely to follow guidance from educators they trust, who show warmth, empathy, and genuine interest in their wellbeing. Natural and logical consequences help children understand the impact of their choices, whereas punishment, time-out, and withdrawal of privileges are not consistent with best practice in ECEC. Teaching social skills explicitly, such as turn-taking, problem-solving, negotiation, and expressing emotions with words, builds children''s capacity to manage their own behaviour over time. Regulation 155 prohibits the use of any form of corporal punishment, unreasonable discipline, or any practice that isolates, humiliates, or frightens a child.', 15),
('b0000071-0000-4000-8000-000000000000', 'a0000018-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000072-0000-4000-8000-000000000000', 'a0000018-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think of a child whose behaviour you find challenging. What might they be communicating through their behaviour, and what strategy could you try to address the underlying need?', 2),

-- Module 19: Supporting Self-Regulation
('b0000073-0000-4000-8000-000000000000', 'a0000019-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Self-regulation is the ability to manage emotions, thoughts, and behaviour in response to different situations. It is a critical developmental skill that underpins learning, social competence, and mental health. Supporting self-regulation in early childhood sets the foundation for lifelong wellbeing.', 7),
('b0000074-0000-4000-8000-000000000000', 'a0000019-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Self-regulation develops gradually and is influenced by brain maturation, temperament, relationships, and the environment; children cannot be expected to regulate emotions they have not yet learned to manage. Co-regulation is the process by which adults help children manage their emotions through calm presence, empathy, and modelling; it is the foundation from which self-regulation develops. Emotional literacy, or the ability to identify and name emotions, is a prerequisite for self-regulation; educators can support this through books, visuals, emotion coaching, and naming feelings throughout the day. Sensory regulation strategies such as quiet spaces, fidget tools, heavy work activities, and deep breathing can support children who are over-stimulated or under-stimulated. Executive function skills, including working memory, cognitive flexibility, and inhibitory control, develop throughout early childhood and are essential components of self-regulation. The environment plays a critical role: predictable routines, calm spaces, reduced sensory overload, and clear transitions support children''s capacity to regulate.', 12),
('b0000075-0000-4000-8000-000000000000', 'a0000019-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000076-0000-4000-8000-000000000000', 'a0000019-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'How do you currently support co-regulation in your room? Is there a calm-down space available, and do children know how to use it independently?', 2),

-- Module 20: Building Partnerships with Families
('b0000077-0000-4000-8000-000000000000', 'a0000020-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Families are children''s first and most influential educators, and genuine partnerships between families and services are essential for children''s learning and wellbeing. QA6 recognises that collaborative relationships with families directly impact the quality of education and care. Building trust takes time, consistency, and genuine respect.', 7),
('b0000078-0000-4000-8000-000000000000', 'a0000020-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Effective family partnerships are characterised by mutual respect, open communication, shared decision-making, and recognition of families'' expertise about their own children. Enrolment and orientation are critical opportunities to begin building relationships: taking time to learn about each family''s values, routines, expectations, and cultural background sets the foundation for partnership. Daily communication, whether verbal, written, or digital, keeps families informed and creates opportunities for two-way sharing about children''s experiences at home and at the service. Families should be genuinely involved in curriculum decisions, not merely informed after the fact; this includes contributing to their child''s learning goals and providing input on program planning. Barriers to family engagement may include language, cultural differences, work schedules, past negative experiences with institutions, or feelings of being unwelcome; services must actively identify and address these barriers. Feedback from families should be sought regularly, valued, and acted upon, with changes communicated back to demonstrate that family input makes a real difference.', 12),
('b0000079-0000-4000-8000-000000000000', 'a0000020-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000080-0000-4000-8000-000000000000', 'a0000020-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about a family you find it challenging to connect with. What might be contributing to the barrier, and what is one step you could take this week to strengthen the relationship?', 2),

-- Module 21: Inclusive Practice & Additional Needs
('b0000081-0000-4000-8000-000000000000', 'a0000021-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Inclusive practice means ensuring that every child can participate fully in the program regardless of ability, background, or circumstance. The NQS requires services to promote equity, respect diversity, and support every child''s right to access quality education and care. Inclusion is not about treating everyone the same; it is about responding to individual needs.', 8),
('b0000082-0000-4000-8000-000000000000', 'a0000021-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The Disability Discrimination Act 1992 and the Disability Standards for Education 2005 require services to make reasonable adjustments to ensure children with disabilities can access and participate in programs on the same basis as other children. Inclusion Support Program (ISP) funding is available to assist services to build their capacity to include children with additional needs, including the Specialist Equipment Library, Inclusion Development Fund, and Innovative Solutions Support. Educators should develop Individual Support Plans or inclusion plans in collaboration with families and allied health professionals, setting achievable goals and documenting strategies and progress. Environmental modifications such as visual schedules, sensory supports, adaptive equipment, and flexible groupings can support the participation of children with additional needs without segregating them. Universal Design for Learning (UDL) principles encourage educators to provide multiple means of engagement, representation, and action and expression so that all children can access learning. Collaboration with external professionals including speech pathologists, occupational therapists, psychologists, and early childhood intervention services strengthens the support available to children and educators.', 18),
('b0000083-0000-4000-8000-000000000000', 'a0000021-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000084-0000-4000-8000-000000000000', 'a0000021-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Consider a child in your room who needs additional support. Are there environmental adjustments or program modifications you could make to enhance their participation?', 4),

-- Module 22: Cultural Competency Foundations
('b0000085-0000-4000-8000-000000000000', 'a0000022-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Australia is one of the most culturally diverse nations in the world, and ECEC services reflect this diversity. Cultural competency is the ability to interact effectively and respectfully with people from different cultural backgrounds. Developing cultural competency is an ongoing journey that enriches both educators'' practice and children''s learning.', 8),
('b0000086-0000-4000-8000-000000000000', 'a0000022-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Cultural competency begins with self-awareness: understanding your own cultural identity, values, biases, and assumptions is the foundation for respectful engagement with others. The EYLF V2.0 emphasises that educators should value the cultural and linguistic diversity of families and use this diversity as a resource for enriching the program for all children. Culturally responsive practice involves learning about and incorporating children''s home languages, cultural practices, celebrations, and ways of knowing into the curriculum. Avoiding a "tourist" approach to culture means going beyond food, flags, and festivals to genuinely embedding cultural perspectives into everyday interactions, environments, and relationships. Working with interpreters and translators may be necessary to ensure effective communication with families who speak languages other than English, and services should know how to access these services. Anti-bias education actively challenges stereotypes, prejudice, and discrimination, empowering children to recognise and stand up against unfairness from an early age.', 15),
('b0000087-0000-4000-8000-000000000000', 'a0000022-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000088-0000-4000-8000-000000000000', 'a0000022-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'How do the resources, images, and materials in your room reflect the cultural diversity of the children and families at your service? What could you add or change?', 2),

-- Module 23: Active Supervision Strategies
('b0000089-0000-4000-8000-000000000000', 'a0000023-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Active supervision goes beyond simply being present in a space. It requires educators to be vigilant, engaged, and strategically positioned to prevent injury and respond quickly to any situation. Effective supervision is one of the most important factors in keeping children safe in ECEC settings.', 5),
('b0000090-0000-4000-8000-000000000000', 'a0000023-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The five key elements of active supervision are positioning (being where you can see and hear all children), scanning (continuously looking around the environment), listening (tuning into sounds that may indicate risk or distress), anticipating (predicting potential hazards based on children''s behaviour and environment), and engaging (interacting with children while maintaining awareness). Educators must be aware of high-risk times and activities including water play, outdoor climbing, sleep and rest, mealtimes, and transitions between activities or spaces. Supervision plans should map out educator positioning for each area and time of day, accounting for toileting, breaks, and non-contact time without compromising ratios. Technology such as phones should never distract from supervision duties; personal devices should be stored away during direct supervision of children. Communication between educators is essential: verbal handovers when moving between areas, clear signals when stepping away, and ensuring no space is left unsupervised. Supervision requirements may vary depending on children''s ages, abilities, and the risk level of the activity or environment; a one-size-fits-all approach is insufficient.', 10),
('b0000091-0000-4000-8000-000000000000', 'a0000023-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 3),
('b0000092-0000-4000-8000-000000000000', 'a0000023-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Map out the supervision zones in your outdoor environment. Are there any blind spots? How does your team communicate when an educator needs to leave the area?', 2),

-- Module 24: Quality Improvement Planning (QIP)
('b0000093-0000-4000-8000-000000000000', 'a0000024-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'The Quality Improvement Plan (QIP) is a living document that records a service''s strengths and identifies areas for improvement against the NQS. Regulation 55 requires every approved service to have a current QIP. Understanding the QIP empowers every educator to contribute to continuous quality improvement.', 8),
('b0000094-0000-4000-8000-000000000000', 'a0000024-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The QIP must include a statement of the service''s philosophy, assessment against each Quality Area including strengths and areas for improvement, and prioritised goals with clear strategies, timelines, and responsibilities. Effective QIPs are developed collaboratively with input from all educators, families, and where appropriate, children and community members, not just the leadership team. Each improvement goal should be specific, measurable, and linked to a Quality Area and element, with clear success indicators and review dates. The QIP should be reviewed and updated regularly, at minimum before an assessment and rating visit, but ideally as an ongoing process at team meetings throughout the year. Evidence of progress towards QIP goals may include updated policies, professional development records, changed practices, family feedback, and children''s learning outcomes. The three Exceeding themes, embedded in service operations, informed by critical reflection, and shaped by meaningful engagement with families and community, should guide how services approach quality improvement.', 15),
('b0000095-0000-4000-8000-000000000000', 'a0000024-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000096-0000-4000-8000-000000000000', 'a0000024-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Have you read your service''s current QIP? Can you identify one goal that relates directly to your practice, and what you are doing to contribute to it?', 2),

-- Module 25: ECA Code of Ethics & Professional Standards
('b0000097-0000-4000-8000-000000000000', 'a0000025-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'The Early Childhood Australia (ECA) Code of Ethics provides a framework for ethical decision-making in ECEC. It articulates the profession''s core values and guides educators in navigating complex situations. Professional standards complement the Code by defining what quality practice looks like at different career stages.', 7),
('b0000098-0000-4000-8000-000000000000', 'a0000025-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The ECA Code of Ethics is organised around commitments to children, families, colleagues, communities and society, and the profession, with each section containing specific ethical responsibilities. Core values underpinning the Code include respect, democracy, honesty, integrity, justice, courage, and inclusiveness, which should guide all professional interactions and decisions. Ethical dilemmas arise when two or more values or commitments conflict; the Code provides a framework for reflecting on and resolving these tensions rather than prescribing specific answers. Professional boundaries are essential: educators must maintain appropriate relationships with families and children that are warm and respectful but recognise the professional nature of the role. Confidentiality is a professional obligation; information about children and families should only be shared on a need-to-know basis and in accordance with privacy legislation and service policies. Advocacy is a professional responsibility: the Code calls on educators to speak up for children''s rights, quality conditions, and the professionalisation of the early childhood sector.', 12),
('b0000099-0000-4000-8000-000000000000', 'a0000025-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000100-0000-4000-8000-000000000000', 'a0000025-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think of a time when you faced an ethical dilemma at work. How did you resolve it, and how might the ECA Code of Ethics have informed your decision?', 2),

-- Module 26: Service Induction
('b0000101-0000-4000-8000-000000000000', 'a0000026-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'A thorough induction ensures that new team members understand the service''s philosophy, policies, procedures, and expectations from their first day. Quality induction supports educator confidence, consistency of practice, and positive outcomes for children. It is a key element of QA4 and QA7, demonstrating effective staffing and governance.', 10),
('b0000102-0000-4000-8000-000000000000', 'a0000026-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Induction should cover the service philosophy, organisational structure, policies and procedures, daily routines, emergency procedures, and expectations for professional conduct. New educators must be introduced to child protection and mandatory reporting procedures, including how to identify and report concerns at the specific service. Orientation to the physical environment includes room layouts, emergency exits, first aid kit locations, safety equipment, outdoor areas, and any hazards specific to the service. Understanding the service''s approach to programming, documentation, and assessment ensures new educators can contribute to the educational program from the start. Administrative requirements including timesheets, leave procedures, communication platforms, and professional development expectations should be clearly explained. A buddy or mentor system pairs new educators with experienced team members for ongoing support during the induction period, which should last at least the first four to six weeks.', 25),
('b0000103-0000-4000-8000-000000000000', 'a0000026-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000104-0000-4000-8000-000000000000', 'a0000026-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think back to your own induction experience. What was most helpful, and what information did you wish you had received earlier?', 5),

-- Module 27: Critical Reflection for Educators
('b0000105-0000-4000-8000-000000000000', 'a0000027-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Critical reflection goes beyond surface-level thinking about practice to examine the assumptions, values, and theories that underpin our decisions. It is identified by ACECQA as one of three key themes for achieving an Exceeding rating. Developing critical reflection skills transforms everyday practice into a source of ongoing professional growth.', 8),
('b0000106-0000-4000-8000-000000000000', 'a0000027-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Critical reflection involves asking "why" and "what if" questions about practice, not just "what" happened; it challenges taken-for-granted assumptions and examines the impact of decisions on children and families. Theoretical perspectives such as sociocultural theory, poststructuralism, and critical theory provide lenses through which educators can examine their practice and understand children''s learning from multiple viewpoints. Reflective practice can be individual through journaling and self-assessment, or collaborative through team discussions, peer observations, and professional learning communities. The EYLF V2.0 identifies ongoing learning and reflective practice as a principle, emphasising that educators who reflect on their practice are more responsive and effective. Critical reflection should inform the QIP: when teams reflect critically on their practice, they identify meaningful areas for improvement rather than surface-level compliance actions. Barriers to critical reflection include time pressure, fear of judgement, lack of facilitation skills, and comfort with existing routines; leaders play a key role in creating safe spaces for honest reflection.', 15),
('b0000107-0000-4000-8000-000000000000', 'a0000027-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000108-0000-4000-8000-000000000000', 'a0000027-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Choose a routine moment from today, such as a mealtime or transition. Why do you do it the way you do? What assumptions are you making, and could there be a better approach?', 2),

-- Module 28: Aboriginal & Torres Strait Islander Perspectives
('b0000109-0000-4000-8000-000000000000', 'a0000028-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Aboriginal and Torres Strait Islander peoples are the first Australians, with the oldest continuous living cultures on Earth spanning over 65,000 years. The EYLF V2.0 strengthened the expectation that all services embed Aboriginal and Torres Strait Islander perspectives into curriculum and practice. This is a responsibility for every educator, regardless of the demographic of children enrolled.', 8),
('b0000110-0000-4000-8000-000000000000', 'a0000028-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Acknowledgement of Country should be a meaningful daily practice that recognises the Traditional Custodians of the land on which your service operates and demonstrates respect for Aboriginal and Torres Strait Islander peoples. Embedding Indigenous perspectives means going beyond NAIDOC Week to incorporate Aboriginal and Torres Strait Islander ways of knowing, being, and doing into everyday curriculum, environments, and relationships. Connection to Country is a central concept in Aboriginal and Torres Strait Islander cultures; educators can support this through outdoor learning, nature play, sustainability practices, and learning about the local environment and its significance. Authentic resources include those created by Aboriginal and Torres Strait Islander peoples; avoid stereotypical or tokenistic representations and seek guidance from local communities and organisations. Reconciliation Action Plans (RAPs) provide a structured framework for services to take meaningful action towards reconciliation, and Narragunnawali by Reconciliation Australia offers a free RAP program for early learning services. Building genuine relationships with local Aboriginal and Torres Strait Islander communities, Elders, and organisations is essential for authentic and respectful engagement with Indigenous perspectives.', 18),
('b0000111-0000-4000-8000-000000000000', 'a0000028-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000112-0000-4000-8000-000000000000', 'a0000028-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'How does your service currently embed Aboriginal and Torres Strait Islander perspectives beyond awareness weeks? What is one step you could take to deepen this engagement?', 4),

-- Module 29: Trauma-Informed Practice in Early Childhood
('b0000113-0000-4000-8000-000000000000', 'a0000029-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Many children in ECEC settings have experienced or are experiencing some form of trauma, including family violence, separation, grief, natural disasters, or community trauma. Trauma-informed practice recognises the widespread impact of trauma and creates environments that promote healing, safety, and trust. Understanding trauma helps educators respond with empathy rather than frustration.', 8),
('b0000114-0000-4000-8000-000000000000', 'a0000029-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Adverse Childhood Experiences (ACEs) research demonstrates that exposure to trauma in early childhood can have lasting effects on brain development, attachment, behaviour, learning, and physical health. Trauma responses in young children may present as hypervigilance, withdrawal, aggression, regression, difficulty with transitions, sleep disturbances, or difficulties forming relationships, and these behaviours are survival strategies, not defiance. The four pillars of trauma-informed care are safety (physical and emotional), trustworthiness (consistency and transparency), choice (empowerment and agency), and collaboration (partnership with children and families). Predictable routines, consistent relationships, calm environments, and clear boundaries provide the sense of safety that children affected by trauma need to begin healing. Educators should avoid re-traumatisation by being mindful of triggers, providing advance warning of changes, offering choices, and never using punitive or coercive approaches. Self-care for educators is essential: secondary traumatic stress and compassion fatigue are real risks when working with children who have experienced trauma, and services should provide support and supervision.', 18),
('b0000115-0000-4000-8000-000000000000', 'a0000029-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000116-0000-4000-8000-000000000000', 'a0000029-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Consider a child in your care who displays challenging behaviour. Could their behaviour be a trauma response? How might viewing their behaviour through a trauma-informed lens change your approach?', 4),

-- Module 30: Sustained Shared Thinking & Deep Learning
('b0000117-0000-4000-8000-000000000000', 'a0000030-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Sustained shared thinking is a powerful pedagogical approach where two or more individuals work together intellectually to solve a problem, clarify a concept, or evaluate an activity. Research from the EPPE project identified it as a key factor in effective early childhood programs. It transforms everyday interactions into rich learning opportunities.', 8),
('b0000118-0000-4000-8000-000000000000', 'a0000030-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Sustained shared thinking occurs when adults and children engage in genuine intellectual partnership, with both parties contributing ideas, building on each other''s thinking, and extending understanding together. It requires educators to "tune in" to children''s thinking by listening carefully, observing closely, and being genuinely curious about children''s theories, ideas, and questions. Open-ended questions and thinking prompts such as "I wonder why...", "What do you think about...?", and "How could we find out?" invite children into deeper thinking rather than seeking a right answer. Sustained shared thinking is most likely to occur in warm, trusting relationships where children feel safe to take intellectual risks, make mistakes, and explore ideas freely. It can happen during any part of the day, including routine moments, but is most frequently observed during free play, small group activities, and one-on-one interactions. Documenting episodes of sustained shared thinking provides powerful evidence of deep learning and intentional teaching for portfolios, program documentation, and assessment and rating.', 15),
('b0000119-0000-4000-8000-000000000000', 'a0000030-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000120-0000-4000-8000-000000000000', 'a0000030-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Recall a conversation with a child this week. Did you extend their thinking or close it down? How might you have used sustained shared thinking to deepen the interaction?', 2),

-- Module 31: Educational Leadership in Practice
('b0000121-0000-4000-8000-000000000000', 'a0000031-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Every approved service must designate a suitably qualified and experienced educator as the Educational Leader under Regulation 118. The Educational Leader plays a pivotal role in driving curriculum quality, supporting educators'' professional growth, and championing best practice pedagogy. Effective educational leadership is central to achieving quality outcomes under QA7.', 8),
('b0000122-0000-4000-8000-000000000000', 'a0000031-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'The Educational Leader''s role encompasses leading the development and implementation of the educational program, mentoring educators, facilitating critical reflection, and ensuring the curriculum is informed by the approved learning framework. Educational leadership is distributed, not hierarchical: effective leaders empower all educators to take ownership of curriculum decisions, contribute to programming, and reflect critically on their practice. Leading professional learning involves identifying team development needs, facilitating meaningful professional learning opportunities, and creating a culture where ongoing learning is valued and supported. The Educational Leader should be visible in practice, spending time in rooms observing, modelling, co-teaching, and providing feedback that builds educator confidence and capability. Building a shared understanding of pedagogy across the service ensures consistency of practice while respecting the individual strengths and approaches of each educator. The Educational Leader plays a key role in the QIP, particularly in relation to QA1, by identifying curriculum strengths and areas for improvement and leading strategies to address them.', 15),
('b0000123-0000-4000-8000-000000000000', 'a0000031-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000124-0000-4000-8000-000000000000', 'a0000031-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'How does the Educational Leader at your service support your professional growth? What kind of support would you find most valuable?', 2),

-- Module 32: Environmental Sustainability with Children
('b0000125-0000-4000-8000-000000000000', 'a0000032-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Environmental sustainability is embedded in the EYLF V2.0 and the NQS through QA3, recognising the importance of fostering children''s respect for and connection to the natural environment. ECEC services have a unique opportunity to nurture environmental stewardship in the youngest generation. Sustainable practices benefit children, communities, and the planet.', 7),
('b0000126-0000-4000-8000-000000000000', 'a0000032-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Element 3.2.3 requires that the service cares for the environment and supports children to become environmentally responsible, going beyond recycling to embed sustainability into the curriculum. Nature play and outdoor learning provide rich opportunities for children to develop connections with the natural world through gardening, composting, water conservation, and exploring local ecosystems. Children can be active participants in sustainability practices: involving them in decisions about reducing waste, conserving water, caring for plants and animals, and recycling builds agency and environmental awareness. Embedding sustainability into everyday routines, such as turning off lights, reducing food waste, using sustainable materials, and composting, makes environmental responsibility a visible part of service culture. Aboriginal and Torres Strait Islander perspectives on caring for Country provide a deep and respectful framework for understanding sustainability, connection to land, and intergenerational responsibility. Sustainability extends beyond the environmental to include social sustainability, which encompasses equity, community engagement, wellbeing, and building resilient communities.', 12),
('b0000127-0000-4000-8000-000000000000', 'a0000032-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000128-0000-4000-8000-000000000000', 'a0000032-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'What sustainability practices are currently embedded in your room''s daily routine? How do children actively participate in caring for the environment at your service?', 2),

-- Module 33: Supporting Transitions
('b0000129-0000-4000-8000-000000000000', 'a0000033-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Transitions are significant events in children''s lives that can cause stress and anxiety if not well supported. Whether transitioning from home to care, between rooms, or from early childhood to school, children and families benefit from thoughtful, collaborative transition planning. QA6 recognises the importance of continuity of learning and transitions.', 7),
('b0000130-0000-4000-8000-000000000000', 'a0000033-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Transition to school is a process, not an event; it begins well before the first day of school and continues into the early weeks and months, requiring collaboration between families, ECEC services, and schools. Effective transition strategies include orientation visits, sharing of information about children''s learning and development (with family consent), school readiness programs, and collaborative planning between services and schools. Room-to-room transitions within a service should be gradual and child-paced, with visits to the new room, introduction to new educators, and sharing of information about the child''s routines, interests, and learning. Separation anxiety is a normal developmental response; educators can support children by providing consistent, warm relationships, predictable routines, and comfort objects from home. Families may also experience anxiety during transitions; keeping families informed, involving them in transition planning, and acknowledging their feelings builds confidence and trust. Documenting and sharing transition statements or summaries supports continuity of learning by ensuring the receiving educator or teacher has a picture of the child''s strengths, interests, and learning journey.', 12),
('b0000131-0000-4000-8000-000000000000', 'a0000033-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000132-0000-4000-8000-000000000000', 'a0000033-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about the last transition a child experienced in your service. What strategies did you use, and how did the child and family respond? What would you do differently?', 2),

-- Module 34: Engaging Families in Programming & Assessment
('b0000133-0000-4000-8000-000000000000', 'a0000034-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Genuine family engagement in programming goes beyond sharing finished documentation to actively involving families in curriculum planning and assessment. When families contribute to their child''s learning program, outcomes for children are strengthened. This practice is essential for achieving Exceeding at both QA1 and QA6.', 7),
('b0000134-0000-4000-8000-000000000000', 'a0000034-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Two-way communication about children''s learning should be embedded into daily practice, with families sharing observations from home and educators sharing documentation from the service in an ongoing dialogue. Digital platforms can enhance family engagement by making documentation accessible, inviting comments and contributions, and providing real-time updates on learning experiences. Family input should genuinely influence the program: when a family shares an interest or experience from home, it should be visible in the curriculum planning, with the link made explicit for families. Assessment of children''s learning should incorporate family perspectives: families know their children best and can provide insights into development, interests, and abilities that educators may not observe at the service. Sharing learning goals and intentions with families empowers them to extend learning at home and creates a shared language about children''s development and progress. Services should offer multiple ways for families to engage, recognising that not all families can attend meetings or events; options might include digital communication, written surveys, phone calls, and informal conversations at pick-up and drop-off.', 12),
('b0000135-0000-4000-8000-000000000000', 'a0000034-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000136-0000-4000-8000-000000000000', 'a0000034-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'When was the last time a family''s input directly changed or influenced your program? How do you make it easy for families to contribute to curriculum decisions?', 2),

-- Module 35: Community Partnerships & Referral Pathways
('b0000137-0000-4000-8000-000000000000', 'a0000035-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Strong connections with the broader community enrich the educational program and provide essential support networks for children and families. QA6 recognises that collaborative partnerships with community organisations contribute to children''s learning, wellbeing, and successful transitions. Knowing when and how to refer families to support services is a vital professional skill.', 7),
('b0000138-0000-4000-8000-000000000000', 'a0000035-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Community partnerships may include relationships with local schools, libraries, health services, cultural organisations, environmental groups, businesses, and community centres that contribute to children''s learning experiences. Referral pathways should be established for key services including child and family health, early childhood intervention, speech pathology, occupational therapy, psychology, family support, and domestic violence services. Educators play a key role in identifying when families may benefit from additional support and sensitively raising concerns and providing information about available services. Maintaining an up-to-date community resources directory ensures that educators can quickly access information about local services, eligibility criteria, and referral processes. The Inclusion Support Program and NDIS (National Disability Insurance Scheme) are key government programs that families may be eligible for, and services should be able to provide information and assistance with access. Building reciprocal relationships with community partners, where both parties benefit and contribute, creates sustainable partnerships that enrich the program and support outcomes for children and families.', 12),
('b0000139-0000-4000-8000-000000000000', 'a0000035-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000140-0000-4000-8000-000000000000', 'a0000035-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Does your service have a current community resources directory? Can you name three external services you could refer a family to if they needed support?', 2),

-- Module 36: Mentoring & Coaching Skills for Leaders
('b0000141-0000-4000-8000-000000000000', 'a0000036-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Mentoring and coaching are distinct but complementary approaches to supporting the professional growth of educators. Effective mentoring and coaching build team capability, improve practice quality, and contribute to staff retention and satisfaction. These skills are essential for room leaders, educational leaders, and anyone in a mentoring role.', 8),
('b0000142-0000-4000-8000-000000000000', 'a0000036-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Mentoring is typically a longer-term relationship focused on overall professional development, while coaching is usually more focused and goal-oriented, targeting specific skills or practices. Effective mentors create a safe, trusting relationship where mentees feel comfortable asking questions, sharing challenges, and taking risks in their practice. Coaching conversations use a structured approach such as the GROW model (Goal, Reality, Options, Will) to help educators identify goals, explore current practice, generate strategies, and commit to action. Active listening, open-ended questioning, and reflective feedback are core skills for both mentoring and coaching; telling people what to do is less effective than helping them discover answers through guided inquiry. Observation and feedback are powerful coaching tools: observing practice in action and providing specific, constructive feedback supports targeted improvement and builds educator confidence. Supporting new graduates, students on placement, and less experienced educators through structured mentoring contributes to workforce development and quality improvement across the sector.', 15),
('b0000143-0000-4000-8000-000000000000', 'a0000036-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000144-0000-4000-8000-000000000000', 'a0000036-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about a colleague you currently mentor or support. What approach do you use, and how do you know if your support is making a positive difference to their practice?', 2),

-- Module 37: Risk-Benefit Assessment in Play Environments
('b0000145-0000-4000-8000-000000000000', 'a0000037-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Risk-benefit assessment is an approach that weighs the developmental benefits of challenging play against the potential for harm, rather than simply eliminating all risk. Children need opportunities to assess and manage risk in order to develop resilience, confidence, and physical competence. Finding the balance between safety and challenge is a professional skill.', 7),
('b0000146-0000-4000-8000-000000000000', 'a0000037-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Risk and hazard are different: a risk is something a child can assess and choose to engage with, while a hazard is a danger that the child cannot reasonably be expected to foresee or manage. Risky play serves important developmental purposes: it builds physical skills, develops risk assessment ability, fosters resilience, promotes self-confidence, and supports the development of executive function. Risk-benefit assessment involves identifying the benefits of an activity or environment feature, assessing the potential risks, and determining whether the benefits outweigh the risks with appropriate management strategies in place. Outdoor environments should provide a variety of challenges appropriate to the ages and abilities of the children, including opportunities for climbing, balancing, jumping, sliding, and rough-and-tumble play. Educator attitudes toward risk significantly influence children''s play experiences: overly cautious responses can deprive children of valuable learning opportunities, while negligent approaches compromise safety. Documentation of risk-benefit assessments demonstrates that professional judgement has been applied and provides evidence of thoughtful practice for families and regulators.', 12),
('b0000147-0000-4000-8000-000000000000', 'a0000037-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000148-0000-4000-8000-000000000000', 'a0000037-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about your outdoor environment. Is there an area where you tend to restrict play due to safety concerns? Could a risk-benefit assessment help you find a better balance?', 2),

-- Module 38: Children's Rights, Agency & Participation
('b0000149-0000-4000-8000-000000000000', 'a0000038-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'The United Nations Convention on the Rights of the Child (UNCRC) affirms that children are rights-holders with the right to have their views heard and taken into account in matters that affect them. Supporting children''s agency and participation is fundamental to respectful, rights-based pedagogy. QA5 requires educators to support each child''s dignity and right to be active participants in their own learning.', 7),
('b0000150-0000-4000-8000-000000000000', 'a0000038-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Article 12 of the UNCRC states that children have the right to express their views freely in all matters affecting them, and these views should be given due weight in accordance with the child''s age and maturity. Agency refers to children''s capacity to make choices, influence events, and act independently within their environment; it requires educators to share power and trust children''s competence. Participation goes beyond giving children choices between two options; it means genuinely including children in decision-making about their learning, environment, routines, and rules. Educators can support agency by providing open-ended materials, flexible routines, child-led play, opportunities for self-help, and environments that children can modify and arrange themselves. Listening to children requires more than hearing their words; it involves observing body language, interpreting play narratives, and creating multiple ways for children to communicate their ideas and feelings. Documenting children''s voices, including their ideas, questions, theories, and preferences, provides evidence that children are active participants in the program and influences the planning cycle.', 12),
('b0000151-0000-4000-8000-000000000000', 'a0000038-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000152-0000-4000-8000-000000000000', 'a0000038-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'How much genuine choice and decision-making power do children have in your room? Identify one routine or practice where you could increase children''s agency.', 2),

-- Module 39: Leading Change & Continuous Improvement
('b0000153-0000-4000-8000-000000000000', 'a0000039-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Change is a constant in the ECEC sector, driven by regulatory updates, research findings, community expectations, and quality improvement goals. Leading change effectively requires understanding how people respond to change and using strategies that build commitment rather than compliance. This module supports current and aspiring leaders to drive meaningful improvement.', 8),
('b0000154-0000-4000-8000-000000000000', 'a0000039-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Successful change initiatives begin with a clear vision and a compelling reason for change that connects to the service''s values, goals, and commitment to children and families. Kotter''s eight-step change model provides a useful framework: create urgency, form a guiding coalition, develop a vision, communicate the vision, empower action, generate short-term wins, consolidate gains, and anchor change in culture. Resistance to change is natural and should be expected; common sources include fear of the unknown, loss of competence, increased workload, disagreement with the direction, or past negative experiences with change. Building team commitment involves involving educators in identifying the need for change, co-designing solutions, and sharing ownership of the implementation process. Short-term wins are critical for maintaining momentum: identifying and celebrating early successes demonstrates that the change is worthwhile and builds confidence for further improvement. Sustainable change requires embedding new practices into policies, systems, and culture; without this anchoring, services risk reverting to old habits when the initial enthusiasm fades.', 15),
('b0000155-0000-4000-8000-000000000000', 'a0000039-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000156-0000-4000-8000-000000000000', 'a0000039-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Think about a recent change at your service. Was it well led? What helped or hindered the team''s acceptance of the change?', 2),

-- Module 40: Philosophy Development & Review
('b0000157-0000-4000-8000-000000000000', 'a0000040-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'A service philosophy is a statement of the beliefs, values, and aspirations that guide every aspect of education and care at the service. Element 7.1.1 requires that a statement of philosophy guides all aspects of the service''s operations. A well-crafted philosophy is a living document that reflects the collective voice of educators, families, and community.', 7),
('b0000158-0000-4000-8000-000000000000', 'a0000040-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'An effective philosophy articulates the service''s beliefs about children, childhood, learning, families, community, and the role of educators, and connects these to the approved learning framework and the NQS. Philosophy development should be a collaborative process that includes the perspectives of educators, families, children (where appropriate), and community members, ensuring shared ownership and commitment. The philosophy should be a practical guide, not a document that sits in a drawer; it should visibly influence decision-making, programming, environment design, and interactions with children and families. Regular review of the philosophy, at least annually, ensures it remains current and responsive to the evolving context of the service, including changes in the team, families, and community. Connecting the philosophy to daily practice requires educators to understand what the philosophy means in practical terms: how does the belief that "children are capable and competent" translate into classroom interactions? Philosophy review is an opportunity for critical reflection: challenging assumptions, examining whether stated beliefs align with actual practice, and identifying gaps between aspiration and reality.', 12),
('b0000159-0000-4000-8000-000000000000', 'a0000040-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 4),
('b0000160-0000-4000-8000-000000000000', 'a0000040-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'Can you recite the key beliefs in your service''s philosophy? Choose one statement and consider whether your daily practice truly reflects it.', 2),

-- Module 41: Performance Review & PDP Development
('b0000161-0000-4000-8000-000000000000', 'a0000041-0000-4000-8000-000000000000', 0, 'content', 'Introduction', 'Performance reviews and Professional Development Plans (PDPs) are essential tools for supporting educator growth, building team capability, and demonstrating commitment to QA4 and QA7. Effective performance management is not about judgement; it is about creating a culture of continuous learning and professional accountability. Every educator deserves meaningful feedback and a clear development pathway.', 8),
('b0000162-0000-4000-8000-000000000000', 'a0000041-0000-4000-8000-000000000000', 1, 'content', 'Key Concepts', 'Performance reviews should be conducted at least annually and include self-assessment, observation of practice, discussion of strengths and areas for growth, and agreement on development goals. A Professional Development Plan (PDP) sets out individual learning goals linked to the educator''s identified areas for growth, the service''s QIP priorities, and the NQS. SMART goals (Specific, Measurable, Achievable, Relevant, Time-bound) provide a framework for writing meaningful development goals that can be tracked and achieved. PDPs should identify a range of professional learning strategies, not just formal training: mentoring, peer observation, reading, online learning, action research, and collaborative projects all contribute to professional growth. Regular check-ins between reviews, at least quarterly, ensure that PDP goals remain relevant, progress is monitored, and support is provided to address barriers. Documentation of professional development activities, reflections on learning, and evidence of changed practice should be maintained to demonstrate ongoing commitment to professional growth and inform the next review.', 15),
('b0000163-0000-4000-8000-000000000000', 'a0000041-0000-4000-8000-000000000000', 2, 'quiz', 'Knowledge Check', NULL, 5),
('b0000164-0000-4000-8000-000000000000', 'a0000041-0000-4000-8000-000000000000', 3, 'reflection', 'Reflect on Your Practice', 'When was your last performance review? Do you have a current PDP with clear goals? If not, what is one professional development goal you could set for yourself this term?', 2);


-- ============================================
-- 3. QUIZ QUESTIONS (3 per module = 123 total)
-- ============================================

INSERT INTO lms_quiz_questions (id, section_id, question, question_type, options, sort_order) VALUES

-- Module 1: First Aid in Education & Care (HLTAID012) - quiz section b0000003
('c0000001-0000-4000-8000-000000000000', 'b0000003-0000-4000-8000-000000000000', 'Under the National Regulations, how many educators with a current approved first aid qualification must be in attendance at all times?', 'multiple_choice', '[{"text":"All educators on shift","is_correct":false,"explanation":"Not all educators are required to hold first aid, but the service must have adequate coverage."},{"text":"At least one","is_correct":true,"explanation":"Regulation 136 requires at least one educator with an approved first aid qualification to be in attendance at all times children are being educated and cared for."},{"text":"At least two","is_correct":false,"explanation":"The minimum requirement is one, though services may choose to have more as best practice."},{"text":"Only the nominated supervisor","is_correct":false,"explanation":"The requirement applies to educators, not specifically the nominated supervisor."}]', 0),
('c0000002-0000-4000-8000-000000000000', 'b0000003-0000-4000-8000-000000000000', 'What does the acronym DRSABCD stand for in first aid?', 'multiple_choice', '[{"text":"Danger, Response, Send for help, Airway, Breathing, CPR, Defibrillation","is_correct":true,"explanation":"DRSABCD is the standard action plan for emergency first aid response in Australia."},{"text":"Danger, Rescue, Safety, Assessment, Breathing, Compression, Doctor","is_correct":false,"explanation":"This is not the correct sequence. The correct acronym is Danger, Response, Send for help, Airway, Breathing, CPR, Defibrillation."},{"text":"Danger, Response, Stabilise, Assess, Bandage, Call, Document","is_correct":false,"explanation":"This is not the correct first aid action plan."},{"text":"Detect, Respond, Support, Administer, Breathe, Check, Debrief","is_correct":false,"explanation":"This is not the standard first aid acronym used in Australia."}]', 1),
('c0000003-0000-4000-8000-000000000000', 'b0000003-0000-4000-8000-000000000000', 'Which regulation requires services to maintain an incident, injury, trauma and illness record?', 'multiple_choice', '[{"text":"Regulation 136","is_correct":false,"explanation":"Regulation 136 relates to first aid qualifications, not incident records."},{"text":"Regulation 168","is_correct":false,"explanation":"Regulation 168 relates to policies and procedures that must be in place at the service."},{"text":"Regulation 87","is_correct":true,"explanation":"Regulation 87 sets out the requirements for the incident, injury, trauma and illness record, including the details that must be recorded."},{"text":"Regulation 77","is_correct":false,"explanation":"Regulation 77 relates to health, hygiene and safe food practices."}]', 2),

-- Module 2: CPR Refresher (HLTAID009) - quiz section b0000007
('c0000004-0000-4000-8000-000000000000', 'b0000007-0000-4000-8000-000000000000', 'What is the correct compression-to-breath ratio for infant and child CPR?', 'multiple_choice', '[{"text":"15:2","is_correct":false,"explanation":"15:2 is the ratio used by healthcare professionals for two-rescuer paediatric CPR, not the standard single-rescuer ratio."},{"text":"30:2","is_correct":true,"explanation":"The compression-to-breath ratio for single-rescuer CPR on infants and children is 30 compressions to 2 breaths."},{"text":"30:1","is_correct":false,"explanation":"The correct ratio includes 2 rescue breaths, not 1."},{"text":"15:1","is_correct":false,"explanation":"This is not the recommended ratio for CPR in Australia."}]', 0),
('c0000005-0000-4000-8000-000000000000', 'b0000007-0000-4000-8000-000000000000', 'At what rate should chest compressions be delivered during CPR?', 'multiple_choice', '[{"text":"60-80 per minute","is_correct":false,"explanation":"This rate is too slow for effective CPR."},{"text":"80-100 per minute","is_correct":false,"explanation":"This is slightly below the recommended rate."},{"text":"100-120 per minute","is_correct":true,"explanation":"Current guidelines recommend compressions at a rate of 100-120 per minute for effective CPR."},{"text":"120-150 per minute","is_correct":false,"explanation":"This rate is too fast and may reduce the effectiveness of compressions."}]', 1),
('c0000006-0000-4000-8000-000000000000', 'b0000007-0000-4000-8000-000000000000', 'How often must CPR training be renewed for educators in ECEC settings?', 'multiple_choice', '[{"text":"Every 6 months","is_correct":false,"explanation":"While more frequent practice is beneficial, the regulatory requirement is annual."},{"text":"Annually","is_correct":true,"explanation":"Under Regulation 137, approved CPR training must be renewed every 12 months."},{"text":"Every 2 years","is_correct":false,"explanation":"CPR certification must be renewed annually, unlike first aid which is triennial."},{"text":"Every 3 years","is_correct":false,"explanation":"Three years is the renewal period for first aid (HLTAID012), not CPR."}]', 2),

-- Module 3: Anaphylaxis Management - quiz section b0000011
('c0000007-0000-4000-8000-000000000000', 'b0000011-0000-4000-8000-000000000000', 'What is the first action you should take when a child shows signs of anaphylaxis?', 'multiple_choice', '[{"text":"Call the child''s parents immediately","is_correct":false,"explanation":"While parents should be notified, the first priority is administering the adrenaline auto-injector."},{"text":"Administer the adrenaline auto-injector (EpiPen)","is_correct":true,"explanation":"The first action is to administer the adrenaline auto-injector, then call 000 for an ambulance."},{"text":"Call 000 for an ambulance","is_correct":false,"explanation":"Calling 000 is the second step; adrenaline must be administered first as delays can be fatal."},{"text":"Give the child antihistamine medication","is_correct":false,"explanation":"Antihistamines are not sufficient for anaphylaxis. Adrenaline is the only effective first-line treatment."}]', 0),
('c0000008-0000-4000-8000-000000000000', 'b0000011-0000-4000-8000-000000000000', 'What dose of adrenaline auto-injector is recommended for a child weighing 15kg?', 'multiple_choice', '[{"text":"EpiPen (0.3mg)","is_correct":false,"explanation":"The full-dose EpiPen is for individuals over 20kg."},{"text":"EpiPen Jr (0.15mg)","is_correct":true,"explanation":"EpiPen Jr (0.15mg) is recommended for children weighing between 7.5kg and 20kg."},{"text":"Half an EpiPen (0.15mg)","is_correct":false,"explanation":"You should never attempt to give a partial dose of an EpiPen. Use the correct device for the child''s weight."},{"text":"No adrenaline should be given at this weight","is_correct":false,"explanation":"A 15kg child is within the weight range for EpiPen Jr (7.5-20kg)."}]', 1),
('c0000009-0000-4000-8000-000000000000', 'b0000011-0000-4000-8000-000000000000', 'Which type of action plan must each child at risk of anaphylaxis have at the service?', 'multiple_choice', '[{"text":"A general allergy awareness plan","is_correct":false,"explanation":"A general plan is not sufficient; each child needs an individual, doctor-completed ASCIA Action Plan."},{"text":"An ASCIA Action Plan for Anaphylaxis","is_correct":true,"explanation":"Each child at risk must have a current ASCIA Action Plan for Anaphylaxis completed by their doctor, which must be displayed and accessible."},{"text":"A parent-written allergy list","is_correct":false,"explanation":"While family input is important, the action plan must be completed by the child''s medical practitioner."},{"text":"A service-developed emergency procedure","is_correct":false,"explanation":"The action plan must be an ASCIA Action Plan completed by the child''s doctor, not a service-developed document."}]', 2),

-- Module 4: Emergency Asthma Management - quiz section b0000015
('c0000010-0000-4000-8000-000000000000', 'b0000015-0000-4000-8000-000000000000', 'What is the correct asthma first aid protocol?', 'multiple_choice', '[{"text":"2 puffs, wait 2 minutes, repeat","is_correct":false,"explanation":"The correct protocol is 4 puffs, wait 4 minutes, and repeat if needed."},{"text":"4 puffs, wait 4 minutes, repeat if no improvement","is_correct":true,"explanation":"The 4x4x4 protocol: give 4 puffs of blue reliever via spacer, wait 4 minutes, give 4 more puffs if no improvement, and continue until ambulance arrives."},{"text":"6 puffs, wait 6 minutes, repeat","is_correct":false,"explanation":"This exceeds the recommended dose per cycle. The correct protocol uses 4 puffs."},{"text":"1 puff every minute until improvement","is_correct":false,"explanation":"This is not the correct protocol. The standard approach is 4 puffs at a time with 4-minute intervals."}]', 0),
('c0000011-0000-4000-8000-000000000000', 'b0000015-0000-4000-8000-000000000000', 'Which of the following is a warning sign of a severe asthma attack in a child?', 'multiple_choice', '[{"text":"Mild wheeze that responds to reliever","is_correct":false,"explanation":"A mild wheeze that responds to reliever medication indicates the asthma is being managed, not worsening."},{"text":"Occasional coughing during outdoor play","is_correct":false,"explanation":"Occasional coughing may be a symptom but is not necessarily a sign of a severe attack."},{"text":"Inability to speak in full sentences and lips turning blue","is_correct":true,"explanation":"Inability to speak in full sentences, blue lips, and increasing distress are warning signs of a severe asthma attack requiring urgent medical attention."},{"text":"Runny nose and sneezing","is_correct":false,"explanation":"These are typically symptoms of a cold or allergies rather than a severe asthma attack."}]', 1),
('c0000012-0000-4000-8000-000000000000', 'b0000015-0000-4000-8000-000000000000', 'What colour is the reliever medication puffer commonly used in asthma first aid?', 'multiple_choice', '[{"text":"Brown","is_correct":false,"explanation":"Brown or orange puffers are typically preventer medications, not relievers."},{"text":"Red","is_correct":false,"explanation":"Red puffers are not standard reliever medications in Australia."},{"text":"Blue","is_correct":true,"explanation":"The blue reliever puffer (salbutamol/Ventolin) is used in asthma first aid and provides quick relief by opening the airways."},{"text":"Purple","is_correct":false,"explanation":"Purple puffers are typically combination preventer medications, not reliever medications."}]', 2),

-- Module 5: ACECQA Foundations of Child Safety - quiz section b0000019
('c0000013-0000-4000-8000-000000000000', 'b0000019-0000-4000-8000-000000000000', 'How many National Principles for Child Safe Organisations are there?', 'multiple_choice', '[{"text":"Five","is_correct":false,"explanation":"There are ten National Principles, not five."},{"text":"Seven","is_correct":false,"explanation":"There are ten National Principles, not seven (seven is the number of NQS Quality Areas)."},{"text":"Ten","is_correct":true,"explanation":"The National Principles for Child Safe Organisations comprise ten principles covering leadership, participation, equity, safety, and improvement."},{"text":"Twelve","is_correct":false,"explanation":"There are ten National Principles for Child Safe Organisations."}]', 0),
('c0000014-0000-4000-8000-000000000000', 'b0000019-0000-4000-8000-000000000000', 'Which of the following best describes a child safe culture?', 'multiple_choice', '[{"text":"Having a child protection policy displayed on the wall","is_correct":false,"explanation":"A policy on the wall is a starting point but does not constitute a culture. A child safe culture is embedded in all aspects of operations."},{"text":"Child safety embedded in leadership, governance, and every aspect of operations","is_correct":true,"explanation":"A child safe culture requires that child safety is embedded in leadership, governance, and organisational culture, not treated as a standalone policy."},{"text":"Conducting annual staff training on child safety","is_correct":false,"explanation":"While training is important, a child safe culture goes beyond annual training to permeate all aspects of the service."},{"text":"Having security cameras installed throughout the service","is_correct":false,"explanation":"Physical security measures alone do not create a child safe culture, which requires systemic and relational approaches."}]', 1),
('c0000015-0000-4000-8000-000000000000', 'b0000019-0000-4000-8000-000000000000', 'Who has responsibility for child safety in an education and care service?', 'multiple_choice', '[{"text":"Only the nominated supervisor","is_correct":false,"explanation":"Child safety is a shared responsibility, not limited to the nominated supervisor."},{"text":"Only educators with direct care responsibilities","is_correct":false,"explanation":"Child safety extends beyond direct care to include all adults in the service environment."},{"text":"All adults including educators, volunteers, students, contractors, and families","is_correct":true,"explanation":"All adults in the service have a shared responsibility for child safety, regardless of their role."},{"text":"Only those who have completed child safety training","is_correct":false,"explanation":"While training is important, all adults share responsibility for child safety regardless of training status."}]', 2),

-- Module 6: ACECQA Advanced Child Safety - quiz section b0000023
('c0000016-0000-4000-8000-000000000000', 'b0000023-0000-4000-8000-000000000000', 'What is the primary responsibility of approved providers and persons with management or control regarding child safety?', 'multiple_choice', '[{"text":"Delegating child safety responsibilities to room leaders","is_correct":false,"explanation":"Governance accountability means actively leading, not merely delegating, child safe practices."},{"text":"Actively leading child safe practices throughout the organisation","is_correct":true,"explanation":"Approved providers and persons with management or control must actively lead child safe practices, not merely delegate responsibility."},{"text":"Ensuring all staff have completed online training","is_correct":false,"explanation":"While training is important, governance accountability requires active leadership beyond ensuring training completion."},{"text":"Conducting annual child safety audits only","is_correct":false,"explanation":"Child safety audits should be regular, not annual only, and governance accountability extends well beyond auditing."}]', 0),
('c0000017-0000-4000-8000-000000000000', 'b0000023-0000-4000-8000-000000000000', 'What is a key characteristic of robust complaint handling procedures in child safe organisations?', 'multiple_choice', '[{"text":"Complaints are handled only by the approved provider","is_correct":false,"explanation":"Effective complaint handling involves clear pathways and accountability, not restriction to a single person."},{"text":"Accessible, transparent, and responsive with clear pathways for raising concerns without fear of reprisal","is_correct":true,"explanation":"Robust complaint handling must be accessible, transparent, and responsive, with clear pathways for children, families, and staff to raise concerns without fear of reprisal."},{"text":"All complaints are kept confidential from the regulatory authority","is_correct":false,"explanation":"Serious complaints may need to be reported to the regulatory authority. Confidentiality does not mean withholding from regulators."},{"text":"Complaints are documented but no feedback is provided to the complainant","is_correct":false,"explanation":"Responsive complaint handling includes providing feedback and following up with the complainant."}]', 1),
('c0000018-0000-4000-8000-000000000000', 'b0000023-0000-4000-8000-000000000000', 'Where should child safety strategies be documented as part of continuous improvement?', 'multiple_choice', '[{"text":"In a separate child safety folder only","is_correct":false,"explanation":"Child safety should be embedded in the QIP as part of continuous improvement, not isolated in a separate folder."},{"text":"In the Quality Improvement Plan (QIP)","is_correct":true,"explanation":"Embedding child safety into the QIP ensures strategies are documented, assigned, monitored, and reviewed as part of the continuous improvement cycle."},{"text":"In staff meeting minutes only","is_correct":false,"explanation":"While team discussions are valuable, strategies should be formally documented in the QIP for accountability and monitoring."},{"text":"In the service philosophy only","is_correct":false,"explanation":"The philosophy may reference child safety values, but strategies and actions belong in the QIP."}]', 2),

-- Module 7: Child Protection & Mandatory Reporting - quiz section b0000027
('c0000019-0000-4000-8000-000000000000', 'b0000027-0000-4000-8000-000000000000', 'What level of certainty is required to make a mandatory report?', 'multiple_choice', '[{"text":"Absolute proof of abuse or neglect","is_correct":false,"explanation":"Mandatory reporters do not need proof. A reasonable suspicion is sufficient to trigger the obligation to report."},{"text":"Confirmation from the child that abuse has occurred","is_correct":false,"explanation":"A child does not need to disclose abuse for a report to be made. Observable indicators and professional judgement are sufficient."},{"text":"Reasonable grounds to suspect a child is at risk of significant harm","is_correct":true,"explanation":"Mandatory reporters must report when they have reasonable grounds to suspect a child is at risk of significant harm. Proof is not required."},{"text":"Agreement from your supervisor that a report should be made","is_correct":false,"explanation":"While consulting with supervisors is good practice, the obligation to report is individual and does not require supervisor agreement."}]', 0),
('c0000020-0000-4000-8000-000000000000', 'b0000027-0000-4000-8000-000000000000', 'Which of the following is NOT one of the four types of child abuse?', 'multiple_choice', '[{"text":"Physical abuse","is_correct":false,"explanation":"Physical abuse is one of the four recognised types of child abuse."},{"text":"Emotional or psychological abuse","is_correct":false,"explanation":"Emotional or psychological abuse is one of the four recognised types."},{"text":"Financial abuse","is_correct":true,"explanation":"The four types of child abuse are physical abuse, emotional/psychological abuse, sexual abuse, and neglect. Financial abuse is not one of the recognised categories in child protection frameworks."},{"text":"Neglect","is_correct":false,"explanation":"Neglect is one of the four recognised types of child abuse."}]', 1),
('c0000021-0000-4000-8000-000000000000', 'b0000027-0000-4000-8000-000000000000', 'What legal protection is provided to mandatory reporters?', 'multiple_choice', '[{"text":"None; reporters can be identified and may face legal action","is_correct":false,"explanation":"Mandatory reporters are protected by law. Their identity cannot be disclosed."},{"text":"The reporter''s identity is protected by law and it is an offence to disclose it","is_correct":true,"explanation":"Legislation protects the identity of mandatory reporters. It is an offence to reveal who made a report."},{"text":"Protection only if the report is substantiated","is_correct":false,"explanation":"Protection is provided regardless of whether the report is substantiated, as long as the report was made in good faith."},{"text":"Protection only if approved by the nominated supervisor","is_correct":false,"explanation":"Legal protection is automatic for good-faith reports and does not require supervisor approval."}]', 2),

-- Module 8: Working with Children Check Obligations - quiz section b0000031
('c0000022-0000-4000-8000-000000000000', 'b0000031-0000-4000-8000-000000000000', 'When must a person hold a valid Working with Children Check?', 'multiple_choice', '[{"text":"Within the first month of starting work","is_correct":false,"explanation":"A valid WWCC must be held before commencing in a child-related role, not after starting."},{"text":"Before commencing in a child-related role","is_correct":true,"explanation":"All staff, volunteers, and students must hold a valid WWCC before commencing in a child-related role."},{"text":"Only after completing a probation period","is_correct":false,"explanation":"There is no probation exemption. A valid WWCC is required before starting work with children."},{"text":"Only if working directly with children under 5","is_correct":false,"explanation":"The WWCC requirement applies to all child-related work regardless of the age of children."}]', 0),
('c0000023-0000-4000-8000-000000000000', 'b0000031-0000-4000-8000-000000000000', 'What must happen if a person''s WWCC is revoked or suspended?', 'multiple_choice', '[{"text":"They can continue working while they appeal the decision","is_correct":false,"explanation":"A person whose WWCC is revoked or suspended must immediately cease working with children."},{"text":"They must immediately cease working with children","is_correct":true,"explanation":"If a person''s WWCC is revoked, cancelled, or suspended, they must immediately cease working with children and the approved provider must be notified."},{"text":"They can work under direct supervision until a new check is obtained","is_correct":false,"explanation":"There is no supervision exemption. The person must stop working with children immediately."},{"text":"They have 30 days to obtain a new clearance","is_correct":false,"explanation":"Revocation or suspension requires immediate cessation of child-related work."}]', 1),
('c0000024-0000-4000-8000-000000000000', 'b0000031-0000-4000-8000-000000000000', 'Does a WWCC replace all other suitability assessments for staff?', 'multiple_choice', '[{"text":"Yes, it is the only assessment required","is_correct":false,"explanation":"The WWCC does not replace other suitability assessments."},{"text":"Yes, if the person also holds a qualification","is_correct":false,"explanation":"Qualifications and WWCC serve different purposes. Additional assessments are still needed."},{"text":"No, services should also conduct reference checks, interviews, and ongoing supervision","is_correct":true,"explanation":"The WWCC does not replace other suitability assessments; services should also conduct reference checks, interviews, and ongoing supervision."},{"text":"No, but only for management positions","is_correct":false,"explanation":"Additional suitability assessments should be conducted for all positions, not just management."}]', 2),

-- Module 9: Food Safety & Hygiene - quiz section b0000035
('c0000025-0000-4000-8000-000000000000', 'b0000035-0000-4000-8000-000000000000', 'What is the temperature danger zone for food?', 'multiple_choice', '[{"text":"0 to 40 degrees Celsius","is_correct":false,"explanation":"The danger zone starts at 5 degrees, not 0."},{"text":"5 to 60 degrees Celsius","is_correct":true,"explanation":"The temperature danger zone is between 5 and 60 degrees Celsius. Perishable food should not remain in this zone for more than two hours."},{"text":"10 to 70 degrees Celsius","is_correct":false,"explanation":"The correct range is 5 to 60 degrees Celsius."},{"text":"5 to 75 degrees Celsius","is_correct":false,"explanation":"While food should be heated above 75 degrees for safety, the danger zone ends at 60 degrees."}]', 0),
('c0000026-0000-4000-8000-000000000000', 'b0000035-0000-4000-8000-000000000000', 'What is the single most important practice in preventing the spread of infection in food handling?', 'multiple_choice', '[{"text":"Wearing disposable gloves","is_correct":false,"explanation":"While gloves can help, hand hygiene is more important as gloves can give a false sense of security if not changed frequently."},{"text":"Using separate chopping boards","is_correct":false,"explanation":"Separate chopping boards prevent cross-contamination but hand hygiene is the single most important practice."},{"text":"Hand hygiene","is_correct":true,"explanation":"Hand hygiene is the single most important practice in preventing the spread of infection. Hands must be washed before and after handling food."},{"text":"Refrigerating food promptly","is_correct":false,"explanation":"While important for food safety, hand hygiene is the most important practice for preventing infection spread."}]', 1),
('c0000027-0000-4000-8000-000000000000', 'b0000035-0000-4000-8000-000000000000', 'What temperature should refrigerated items be stored below?', 'multiple_choice', '[{"text":"8 degrees Celsius","is_correct":false,"explanation":"8 degrees is too warm. Refrigerated items should be stored below 5 degrees Celsius."},{"text":"5 degrees Celsius","is_correct":true,"explanation":"Refrigerated items must be stored below 5 degrees Celsius to prevent bacterial growth."},{"text":"10 degrees Celsius","is_correct":false,"explanation":"10 degrees is within the temperature danger zone and is not safe for food storage."},{"text":"0 degrees Celsius","is_correct":false,"explanation":"0 degrees is the freezing point. Refrigerated items should be below 5 degrees, while frozen items should be below minus 15 degrees."}]', 2),

-- Module 10: WHS Induction for ECEC - quiz section b0000039
('c0000028-0000-4000-8000-000000000000', 'b0000039-0000-4000-8000-000000000000', 'Under WHS legislation, who has the primary duty to ensure health and safety at the workplace?', 'multiple_choice', '[{"text":"Individual workers","is_correct":false,"explanation":"While workers have duties, the primary duty rests with the PCBU (Person Conducting a Business or Undertaking)."},{"text":"The Person Conducting a Business or Undertaking (PCBU)","is_correct":true,"explanation":"The PCBU, which includes approved providers, has the primary duty to ensure the health and safety of workers and others at the workplace."},{"text":"The WHS regulator","is_correct":false,"explanation":"The regulator enforces WHS legislation but does not have the primary duty for individual workplace safety."},{"text":"The room leader","is_correct":false,"explanation":"Room leaders have duties as workers but the primary duty is with the PCBU."}]', 0),
('c0000029-0000-4000-8000-000000000000', 'b0000039-0000-4000-8000-000000000000', 'What are the four steps in the risk management process?', 'multiple_choice', '[{"text":"Report, investigate, resolve, close","is_correct":false,"explanation":"This describes an incident response process, not the risk management process."},{"text":"Identify hazards, assess the risk, implement controls, review effectiveness","is_correct":true,"explanation":"The risk management process involves identifying hazards, assessing the risk, implementing control measures, and reviewing their effectiveness."},{"text":"Observe, document, notify, follow up","is_correct":false,"explanation":"This is more aligned with incident reporting than risk management."},{"text":"Plan, do, check, act","is_correct":false,"explanation":"PDCA is a quality improvement cycle, not the specific WHS risk management process."}]', 1),
('c0000030-0000-4000-8000-000000000000', 'b0000039-0000-4000-8000-000000000000', 'Which incidents must be reported to the WHS regulator?', 'multiple_choice', '[{"text":"All incidents regardless of severity","is_correct":false,"explanation":"Only notifiable incidents must be reported to the regulator, not all incidents."},{"text":"Only incidents involving children","is_correct":false,"explanation":"Notifiable incidents involving any person at the workplace must be reported, not just those involving children."},{"text":"Notifiable incidents as defined in WHS legislation","is_correct":true,"explanation":"Notifiable incidents, including death, serious injury or illness, and dangerous incidents, must be reported to the WHS regulator."},{"text":"Only incidents that result in workers compensation claims","is_correct":false,"explanation":"Notifiable incidents must be reported regardless of whether a compensation claim is made."}]', 2),

-- Module 11: Safe Sleep & Rest Practices - quiz section b0000043
('c0000031-0000-4000-8000-000000000000', 'b0000043-0000-4000-8000-000000000000', 'According to Red Nose Australia, what is the safest sleeping position for babies?', 'multiple_choice', '[{"text":"On their side","is_correct":false,"explanation":"Side sleeping increases the risk of SIDS as the baby may roll onto their stomach."},{"text":"On their stomach","is_correct":false,"explanation":"Stomach sleeping significantly increases the risk of SIDS."},{"text":"On their back","is_correct":true,"explanation":"Sleeping on the back is the safest position for babies and significantly reduces the risk of SIDS."},{"text":"In any position the child prefers","is_correct":false,"explanation":"Safe sleep guidelines specifically recommend back sleeping regardless of the child''s preference, particularly for infants."}]', 0),
('c0000032-0000-4000-8000-000000000000', 'b0000043-0000-4000-8000-000000000000', 'How frequently should sleep checks typically be conducted during rest time?', 'multiple_choice', '[{"text":"Every 30 minutes","is_correct":false,"explanation":"30-minute intervals are too infrequent for safe sleep monitoring."},{"text":"Every 10-15 minutes","is_correct":true,"explanation":"Sleep checks should be conducted at intervals documented in the service policy, typically every 10-15 minutes, observing breathing, colour, and temperature."},{"text":"Only at the beginning and end of rest time","is_correct":false,"explanation":"Checks must be regular throughout the rest period, not just at the beginning and end."},{"text":"Continuously without interruption","is_correct":false,"explanation":"While constant supervision is ideal, the standard practice is documented checks at regular intervals of 10-15 minutes."}]', 1),
('c0000033-0000-4000-8000-000000000000', 'b0000043-0000-4000-8000-000000000000', 'Should children ever be forced to sleep at rest time?', 'multiple_choice', '[{"text":"Yes, all children need sleep during the day","is_correct":false,"explanation":"Not all children need daytime sleep, and forcing sleep is not appropriate practice."},{"text":"Yes, if parents have requested it","is_correct":false,"explanation":"Even with parent requests, children should not be forced to sleep. The service should discuss rest needs with families."},{"text":"No, children should never be forced to sleep; the focus should be on restful environments","is_correct":true,"explanation":"Children should never be forced to sleep. The focus should be on providing restful, calming environments where children can choose to rest without pressure."},{"text":"Only children under 3 should be required to sleep","is_correct":false,"explanation":"No child of any age should be forced to sleep. Individual sleep plans should guide each child''s rest experience."}]', 2),

-- Module 12: Emergency Evacuation & Lockdown - quiz section b0000047
('c0000034-0000-4000-8000-000000000000', 'b0000047-0000-4000-8000-000000000000', 'How often must emergency and evacuation procedures be rehearsed under the National Regulations?', 'multiple_choice', '[{"text":"Every month","is_correct":false,"explanation":"Monthly rehearsals are not required by regulation, though services may choose to practise more frequently."},{"text":"Every three months","is_correct":true,"explanation":"Regulation 97 requires services to rehearse emergency and evacuation procedures every three months."},{"text":"Every six months","is_correct":false,"explanation":"Six months is too infrequent. The regulatory requirement is every three months."},{"text":"Annually","is_correct":false,"explanation":"Annual rehearsals do not meet the regulatory requirement of every three months."}]', 0),
('c0000035-0000-4000-8000-000000000000', 'b0000047-0000-4000-8000-000000000000', 'When is a lockdown procedure used?', 'multiple_choice', '[{"text":"During a fire emergency","is_correct":false,"explanation":"Fire emergencies require evacuation, not lockdown. Lockdown keeps people inside the building."},{"text":"When there is a threat on or near the premises such as an intruder","is_correct":true,"explanation":"Lockdown procedures are used when there is a threat on or near the premises, such as an intruder, dangerous animal, or nearby police operation."},{"text":"During severe weather warnings","is_correct":false,"explanation":"Severe weather may require sheltering but a formal lockdown is for threats such as intruders."},{"text":"At the end of each day","is_correct":false,"explanation":"Lockdown is an emergency procedure, not a daily routine."}]', 1),
('c0000036-0000-4000-8000-000000000000', 'b0000047-0000-4000-8000-000000000000', 'Why is a current attendance record essential during an emergency?', 'multiple_choice', '[{"text":"For insurance purposes only","is_correct":false,"explanation":"While important for documentation, the primary purpose during an emergency is to account for every person."},{"text":"To account for every child and adult present at the service","is_correct":true,"explanation":"A current attendance record is essential to account for every child and adult, including the daily sign-in register, visitor log, and staff roster."},{"text":"To notify parents in alphabetical order","is_correct":false,"explanation":"Parent notification is important but the primary purpose of the attendance record during an emergency is accountability."},{"text":"It is not essential during emergencies","is_correct":false,"explanation":"Accurate attendance records are critical during emergencies to ensure everyone is accounted for."}]', 2),

-- Module 13: Understanding NQF, NQS & National Regulations - quiz section b0000051
('c0000037-0000-4000-8000-000000000000', 'b0000051-0000-4000-8000-000000000000', 'How many Quality Areas are in the National Quality Standard?', 'multiple_choice', '[{"text":"Five","is_correct":false,"explanation":"There are seven Quality Areas in the NQS, not five."},{"text":"Six","is_correct":false,"explanation":"There are seven Quality Areas in the NQS."},{"text":"Seven","is_correct":true,"explanation":"The NQS contains seven Quality Areas covering educational program, health and safety, physical environment, staffing, relationships, partnerships, and governance."},{"text":"Eight","is_correct":false,"explanation":"There are seven Quality Areas in the NQS."}]', 0),
('c0000038-0000-4000-8000-000000000000', 'b0000051-0000-4000-8000-000000000000', 'What are the three themes required for an Exceeding rating?', 'multiple_choice', '[{"text":"Planning, implementing, and evaluating","is_correct":false,"explanation":"These are stages of the planning cycle, not the Exceeding themes."},{"text":"Embedded practice, critical reflection, and meaningful engagement with families and community","is_correct":true,"explanation":"To achieve Exceeding, practice must be embedded in service operations, informed by critical reflection, and shaped by meaningful engagement with families and community."},{"text":"Documentation, assessment, and reporting","is_correct":false,"explanation":"These relate to QA1 practices, not the three Exceeding themes."},{"text":"Leadership, governance, and management","is_correct":false,"explanation":"These relate to QA7, not the three themes required for an Exceeding rating."}]', 1),
('c0000039-0000-4000-8000-000000000000', 'b0000051-0000-4000-8000-000000000000', 'What are the possible overall ratings a service can receive?', 'multiple_choice', '[{"text":"Below Standard, Standard, Above Standard, Outstanding","is_correct":false,"explanation":"These are not the rating levels used in the NQS."},{"text":"Significant Improvement Required, Working Towards, Meeting, Exceeding, Excellent","is_correct":true,"explanation":"The five rating levels are Significant Improvement Required, Working Towards NQS, Meeting NQS, Exceeding NQS, and Excellent."},{"text":"Unsatisfactory, Satisfactory, Good, Excellent","is_correct":false,"explanation":"These are not the rating levels used under the NQF."},{"text":"Level 1, Level 2, Level 3, Level 4, Level 5","is_correct":false,"explanation":"The NQS uses descriptive rating levels, not numbered levels."}]', 2),

-- Module 14: EYLF V2.0 Framework Essentials - quiz section b0000055
('c0000040-0000-4000-8000-000000000000', 'b0000055-0000-4000-8000-000000000000', 'How many learning outcomes are in the EYLF V2.0?', 'multiple_choice', '[{"text":"Three","is_correct":false,"explanation":"The EYLF V2.0 contains five learning outcomes, not three."},{"text":"Five","is_correct":true,"explanation":"The five learning outcomes cover identity, connection and contribution, wellbeing, confident and involved learners, and effective communicators."},{"text":"Seven","is_correct":false,"explanation":"Seven is the number of NQS Quality Areas, not EYLF learning outcomes."},{"text":"Eight","is_correct":false,"explanation":"Eight is the number of EYLF practices, not learning outcomes."}]', 0),
('c0000041-0000-4000-8000-000000000000', 'b0000055-0000-4000-8000-000000000000', 'What are the three concepts that underpin the EYLF V2.0?', 'multiple_choice', '[{"text":"Play, learning, and development","is_correct":false,"explanation":"While these are important concepts in ECEC, the three underpinning concepts of the EYLF are Belonging, Being, and Becoming."},{"text":"Belonging, Being, and Becoming","is_correct":true,"explanation":"The EYLF V2.0 is underpinned by the concepts of Belonging, Being, and Becoming, reflecting children''s experiences of early childhood."},{"text":"Safety, wellbeing, and learning","is_correct":false,"explanation":"These are important but not the three underpinning concepts of the EYLF."},{"text":"Respect, relationships, and reciprocity","is_correct":false,"explanation":"These are related to the principles but are not the three underpinning concepts."}]', 1),
('c0000042-0000-4000-8000-000000000000', 'b0000055-0000-4000-8000-000000000000', 'Which of the following was strengthened in the EYLF V2.0 compared to V1.0?', 'multiple_choice', '[{"text":"Educator-to-child ratios","is_correct":false,"explanation":"Ratios are set in the National Regulations, not the EYLF."},{"text":"Aboriginal and Torres Strait Islander perspectives, sustainability, and critical reflection","is_correct":true,"explanation":"The EYLF V2.0 strengthened the focus on Aboriginal and Torres Strait Islander perspectives, sustainability, and critical reflection."},{"text":"Physical environment requirements","is_correct":false,"explanation":"Physical environment requirements are addressed in QA3 and the National Regulations, not the EYLF."},{"text":"Staffing qualifications","is_correct":false,"explanation":"Staffing qualifications are set in the National Regulations, not the EYLF."}]', 2),

-- Module 15: The Planning Cycle - quiz section b0000059
('c0000043-0000-4000-8000-000000000000', 'b0000059-0000-4000-8000-000000000000', 'What is the correct order of the planning cycle?', 'multiple_choice', '[{"text":"Plan, implement, observe, analyse, evaluate","is_correct":false,"explanation":"The cycle begins with observation, not planning."},{"text":"Observe, analyse, plan, implement, evaluate","is_correct":true,"explanation":"The planning cycle follows this continuous sequence: observe children, analyse what you observe, plan experiences, implement with intentionality, and evaluate outcomes."},{"text":"Assess, plan, teach, review, report","is_correct":false,"explanation":"This describes a more traditional teaching model, not the responsive ECEC planning cycle."},{"text":"Document, reflect, discuss, plan, implement","is_correct":false,"explanation":"While these are related activities, this is not the standard planning cycle sequence."}]', 0),
('c0000044-0000-4000-8000-000000000000', 'b0000059-0000-4000-8000-000000000000', 'What should be included in the analysis stage of the planning cycle?', 'multiple_choice', '[{"text":"Only a description of what the child did","is_correct":false,"explanation":"Description alone is observation, not analysis. Analysis involves connecting observations to learning outcomes and developmental knowledge."},{"text":"Connections to EYLF learning outcomes, developmental milestones, and individual learning trajectories","is_correct":true,"explanation":"Analysis involves connecting observations to EYLF learning outcomes, considering developmental milestones, and identifying individual learning trajectories."},{"text":"A list of resources needed for the next activity","is_correct":false,"explanation":"Resource lists belong in the planning stage, not the analysis stage."},{"text":"Parent feedback only","is_correct":false,"explanation":"While family input is valuable, analysis involves professional interpretation of observations using theoretical and developmental knowledge."}]', 1),
('c0000045-0000-4000-8000-000000000000', 'b0000059-0000-4000-8000-000000000000', 'Why should planning be responsive and flexible?', 'multiple_choice', '[{"text":"Because regulators prefer flexible programs","is_correct":false,"explanation":"Flexibility is not about regulatory preference but about meeting children''s needs."},{"text":"Because it is easier for educators to manage","is_correct":false,"explanation":"Responsive planning may actually be more demanding for educators but leads to better outcomes for children."},{"text":"To incorporate children''s voices, family input, and spontaneous learning moments","is_correct":true,"explanation":"Planning should be responsive and flexible to incorporate children''s voices, family input, and spontaneous learning moments alongside planned experiences."},{"text":"Because detailed planning is no longer required under the NQS","is_correct":false,"explanation":"The NQS still requires intentional and purposeful planning; responsive planning is thorough, not unplanned."}]', 2),

-- Module 16: Intentional Teaching Strategies - quiz section b0000063
('c0000046-0000-4000-8000-000000000000', 'b0000063-0000-4000-8000-000000000000', 'What is scaffolding in the context of intentional teaching?', 'multiple_choice', '[{"text":"Setting up physical structures for children to climb on","is_correct":false,"explanation":"Scaffolding in teaching is a pedagogical strategy, not a physical structure."},{"text":"Providing temporary support to help children achieve something they cannot yet do independently","is_correct":true,"explanation":"Scaffolding involves providing temporary support to help children achieve something they cannot yet do independently, then gradually withdrawing support as competence grows."},{"text":"Creating a step-by-step lesson plan for each activity","is_correct":false,"explanation":"While planning is important, scaffolding is about responsive, in-the-moment support rather than predetermined steps."},{"text":"Telling children exactly what to do and how to do it","is_correct":false,"explanation":"Scaffolding supports learning through guided assistance, not direct instruction."}]', 0),
('c0000047-0000-4000-8000-000000000000', 'b0000063-0000-4000-8000-000000000000', 'Which of the following is an example of an open-ended question?', 'multiple_choice', '[{"text":"What colour is this block?","is_correct":false,"explanation":"This is a closed question with a single correct answer."},{"text":"Did you enjoy that activity?","is_correct":false,"explanation":"This is a closed yes/no question that does not extend thinking."},{"text":"What do you think might happen if we add more water?","is_correct":true,"explanation":"Open-ended questions like this encourage higher-order thinking, prediction, and exploration rather than seeking a single correct answer."},{"text":"Can you count to ten?","is_correct":false,"explanation":"This is a closed question that tests recall rather than extending thinking."}]', 1),
('c0000048-0000-4000-8000-000000000000', 'b0000063-0000-4000-8000-000000000000', 'What does co-construction of learning involve?', 'multiple_choice', '[{"text":"Educators building structures alongside children","is_correct":false,"explanation":"Co-construction refers to intellectual collaboration, not physical building."},{"text":"Educators and children collaborating as equal partners in exploring ideas and building knowledge","is_correct":true,"explanation":"Co-construction occurs when educators and children collaborate as equal partners in exploring ideas, solving problems, and building knowledge together."},{"text":"Children constructing their own understanding without educator input","is_correct":false,"explanation":"Co-construction involves both educators and children working together, not children working alone."},{"text":"Educators planning activities based on a prescribed curriculum","is_correct":false,"explanation":"Co-construction is responsive and collaborative, not based on a prescribed curriculum."}]', 2),

-- Module 17: Documenting Children's Learning - quiz section b0000067
('c0000049-0000-4000-8000-000000000000', 'b0000067-0000-4000-8000-000000000000', 'What is a learning story?', 'multiple_choice', '[{"text":"A fictional story written about a child","is_correct":false,"explanation":"Learning stories are based on real observations, not fiction."},{"text":"A narrative form of documentation that captures the child''s learning journey including what happened, the learning, and next steps","is_correct":true,"explanation":"Learning stories are a narrative documentation method that captures the child''s learning journey, including what happened, the learning that occurred linked to EYLF outcomes, and planned next steps."},{"text":"A story book that the educator reads to children","is_correct":false,"explanation":"A learning story is a documentation tool, not a children''s book."},{"text":"A weekly report sent home to parents","is_correct":false,"explanation":"While learning stories may be shared with families, they are a specific documentation method, not a generic report."}]', 0),
('c0000050-0000-4000-8000-000000000000', 'b0000067-0000-4000-8000-000000000000', 'What should documentation include to reflect children''s participation?', 'multiple_choice', '[{"text":"Only photographs of children during activities","is_correct":false,"explanation":"Photographs alone do not capture children''s thinking or voice."},{"text":"The child''s voice: their words, ideas, questions, and theories","is_correct":true,"explanation":"Documentation should include the child''s voice through their words, ideas, questions, and theories, captured through dictation, audio, or transcription."},{"text":"Only educator observations and assessments","is_correct":false,"explanation":"Documentation should include the child''s perspective, not just the educator''s observations."},{"text":"Checklists of developmental milestones achieved","is_correct":false,"explanation":"While developmental information is useful, effective documentation goes beyond checklists to capture the child''s voice and learning journey."}]', 1),
('c0000051-0000-4000-8000-000000000000', 'b0000067-0000-4000-8000-000000000000', 'What does effective documentation prioritise?', 'multiple_choice', '[{"text":"Quantity over quality to ensure comprehensive records","is_correct":false,"explanation":"Effective documentation prioritises quality over quantity."},{"text":"Quality over quantity, focusing on significant learning moments","is_correct":true,"explanation":"Effective documentation is timely, meaningful, and manageable, prioritising quality over quantity and focusing on significant learning moments."},{"text":"Meeting regulatory requirements only","is_correct":false,"explanation":"While compliance is important, effective documentation serves multiple purposes including informing planning and communicating with families."},{"text":"Standardised formats that are the same for every child","is_correct":false,"explanation":"Documentation should be individualised to reflect each child''s unique learning journey."}]', 2),

-- Module 18: Positive Behaviour Guidance - quiz section b0000071
('c0000052-0000-4000-8000-000000000000', 'b0000071-0000-4000-8000-000000000000', 'What does the statement "behaviour is communication" mean?', 'multiple_choice', '[{"text":"Children should use words instead of actions to communicate","is_correct":false,"explanation":"This misses the point. The statement means that all behaviour, including challenging behaviour, serves a purpose and communicates something."},{"text":"All behaviour serves a purpose and understanding what a child is communicating is the first step in guidance","is_correct":true,"explanation":"Understanding what a child is trying to communicate through their behaviour is the first step in providing effective positive behaviour guidance."},{"text":"Children need to be taught communication skills before behaviour can improve","is_correct":false,"explanation":"While communication skills are important, the statement refers to understanding the meaning behind all behaviour."},{"text":"Educators should communicate rules more clearly","is_correct":false,"explanation":"The statement is about understanding children''s behaviour, not about educators communicating rules."}]', 0),
('c0000053-0000-4000-8000-000000000000', 'b0000071-0000-4000-8000-000000000000', 'Which of the following is consistent with positive behaviour guidance in ECEC?', 'multiple_choice', '[{"text":"Time-out in a separate area","is_correct":false,"explanation":"Time-out and isolation are not consistent with positive behaviour guidance in ECEC settings."},{"text":"Withdrawal of play privileges","is_correct":false,"explanation":"Withdrawal of privileges is a punitive approach that is not consistent with best practice."},{"text":"Natural and logical consequences that help children understand the impact of their choices","is_correct":true,"explanation":"Natural and logical consequences help children understand the impact of their choices, unlike punishment which relies on fear or loss."},{"text":"Public behaviour charts that rank children","is_correct":false,"explanation":"Public ranking of behaviour can humiliate children and is not consistent with positive behaviour guidance."}]', 1),
('c0000054-0000-4000-8000-000000000000', 'b0000071-0000-4000-8000-000000000000', 'What does Regulation 155 prohibit?', 'multiple_choice', '[{"text":"Outdoor play in hot weather","is_correct":false,"explanation":"Regulation 155 does not address outdoor play conditions."},{"text":"Any form of corporal punishment, unreasonable discipline, or practices that isolate, humiliate, or frighten a child","is_correct":true,"explanation":"Regulation 155 prohibits corporal punishment, unreasonable discipline, and any practice that is designed to isolate, humiliate, or frighten a child."},{"text":"Children playing without direct educator involvement","is_correct":false,"explanation":"Child-initiated play without direct educator involvement is appropriate and valued in ECEC."},{"text":"Raising your voice during emergency situations","is_correct":false,"explanation":"Regulation 155 addresses discipline practices, not emergency communication."}]', 2),

-- Module 19: Supporting Self-Regulation - quiz section b0000075
('c0000055-0000-4000-8000-000000000000', 'b0000075-0000-4000-8000-000000000000', 'What is co-regulation?', 'multiple_choice', '[{"text":"Children regulating each other''s behaviour","is_correct":false,"explanation":"Co-regulation specifically refers to adults helping children manage emotions, not peer regulation."},{"text":"The process by which adults help children manage their emotions through calm presence, empathy, and modelling","is_correct":true,"explanation":"Co-regulation is when adults help children manage their emotions through calm presence, empathy, and modelling. It is the foundation from which self-regulation develops."},{"text":"A regulatory requirement for educator-to-child ratios","is_correct":false,"explanation":"Co-regulation is a developmental concept, not a regulatory requirement."},{"text":"Teaching children to follow rules independently","is_correct":false,"explanation":"Co-regulation is about emotional support, not rule following."}]', 0),
('c0000056-0000-4000-8000-000000000000', 'b0000075-0000-4000-8000-000000000000', 'Which of the following is a component of executive function?', 'multiple_choice', '[{"text":"Gross motor skills","is_correct":false,"explanation":"Gross motor skills are physical development, not executive function."},{"text":"Working memory, cognitive flexibility, and inhibitory control","is_correct":true,"explanation":"Executive function skills include working memory, cognitive flexibility, and inhibitory control, all essential for self-regulation."},{"text":"Language development","is_correct":false,"explanation":"While language supports self-regulation, it is not a component of executive function."},{"text":"Social skills","is_correct":false,"explanation":"Social skills are related but are not the specific components of executive function."}]', 1),
('c0000057-0000-4000-8000-000000000000', 'b0000075-0000-4000-8000-000000000000', 'How does the environment support self-regulation?', 'multiple_choice', '[{"text":"By having strict rules posted on every wall","is_correct":false,"explanation":"Strict rules alone do not support self-regulation development."},{"text":"Through predictable routines, calm spaces, reduced sensory overload, and clear transitions","is_correct":true,"explanation":"Predictable routines, calm spaces, reduced sensory overload, and clear transitions support children''s capacity to regulate."},{"text":"By removing all stimulating materials","is_correct":false,"explanation":"Removing all stimulation is not appropriate; the goal is to reduce sensory overload while providing engaging experiences."},{"text":"By keeping children seated at tables for extended periods","is_correct":false,"explanation":"Restricting movement does not support self-regulation and may actually increase dysregulation."}]', 2),

-- Module 20: Building Partnerships with Families - quiz section b0000079
('c0000058-0000-4000-8000-000000000000', 'b0000079-0000-4000-8000-000000000000', 'What are the key characteristics of effective family partnerships?', 'multiple_choice', '[{"text":"Educators telling families what they need to do at home","is_correct":false,"explanation":"Effective partnerships are not one-directional. They involve mutual respect and shared decision-making."},{"text":"Mutual respect, open communication, shared decision-making, and recognition of family expertise","is_correct":true,"explanation":"Effective partnerships are characterised by mutual respect, open communication, shared decision-making, and recognition of families'' expertise about their own children."},{"text":"Families following the service''s approach to parenting","is_correct":false,"explanation":"Partnerships recognise that families are experts on their own children and do not require them to adopt the service''s approach."},{"text":"Limiting communication to formal parent-teacher meetings","is_correct":false,"explanation":"Effective communication should be ongoing and include daily interactions, not limited to formal meetings."}]', 0),
('c0000059-0000-4000-8000-000000000000', 'b0000079-0000-4000-8000-000000000000', 'What are potential barriers to family engagement?', 'multiple_choice', '[{"text":"Families who are not interested in their children''s education","is_correct":false,"explanation":"This assumption is a barrier in itself. Most families care deeply but may face practical barriers to engagement."},{"text":"Language, cultural differences, work schedules, past negative experiences, or feeling unwelcome","is_correct":true,"explanation":"Barriers may include language, cultural differences, work schedules, past negative experiences with institutions, or feelings of being unwelcome."},{"text":"Educators who share too much information with families","is_correct":false,"explanation":"Sharing information generally supports engagement rather than creating barriers."},{"text":"Children who behave differently at home and at the service","is_correct":false,"explanation":"This is common and does not constitute a barrier to family engagement."}]', 1),
('c0000060-0000-4000-8000-000000000000', 'b0000079-0000-4000-8000-000000000000', 'How should families be involved in curriculum decisions?', 'multiple_choice', '[{"text":"Families should approve all planned activities before they occur","is_correct":false,"explanation":"This level of approval is impractical. Genuine involvement means contributing to decisions, not approving every activity."},{"text":"Families should only be informed after activities have taken place","is_correct":false,"explanation":"Informing after the fact is not genuine involvement in decision-making."},{"text":"Families should be genuinely involved in decisions, not merely informed after the fact","is_correct":true,"explanation":"Families should be genuinely involved in curriculum decisions, including contributing to their child''s learning goals and providing input on program planning."},{"text":"Families should not be involved in curriculum as this is the educator''s professional domain","is_correct":false,"explanation":"Families are recognised as children''s first educators and their input is essential for responsive programming."}]', 2),

-- Module 21: Inclusive Practice & Additional Needs - quiz section b0000083
('c0000061-0000-4000-8000-000000000000', 'b0000083-0000-4000-8000-000000000000', 'What legislation requires services to make reasonable adjustments for children with disabilities?', 'multiple_choice', '[{"text":"The National Quality Standard","is_correct":false,"explanation":"While the NQS promotes inclusion, the specific legal requirement for reasonable adjustments comes from federal legislation."},{"text":"The Disability Discrimination Act 1992 and Disability Standards for Education 2005","is_correct":true,"explanation":"The Disability Discrimination Act 1992 and the Disability Standards for Education 2005 require services to make reasonable adjustments for children with disabilities."},{"text":"The Education and Care Services National Regulations","is_correct":false,"explanation":"While the National Regulations support inclusion, the specific requirement for reasonable adjustments is in disability legislation."},{"text":"The Fair Work Act","is_correct":false,"explanation":"The Fair Work Act relates to employment, not educational access for children with disabilities."}]', 0),
('c0000062-0000-4000-8000-000000000000', 'b0000083-0000-4000-8000-000000000000', 'What is the Inclusion Support Program (ISP)?', 'multiple_choice', '[{"text":"A staff training program for special education teachers","is_correct":false,"explanation":"The ISP is not a training program; it provides funding and support to build service capacity for inclusion."},{"text":"A government program that assists services to build capacity to include children with additional needs","is_correct":true,"explanation":"The ISP provides funding and support including the Specialist Equipment Library, Inclusion Development Fund, and Innovative Solutions Support to help services include children with additional needs."},{"text":"A curriculum framework for children with disabilities","is_correct":false,"explanation":"The ISP is a funding and support program, not a curriculum framework."},{"text":"A mandatory assessment tool for identifying disabilities","is_correct":false,"explanation":"The ISP is not an assessment tool; it provides resources and funding to support inclusion."}]', 1),
('c0000063-0000-4000-8000-000000000000', 'b0000083-0000-4000-8000-000000000000', 'What does Universal Design for Learning (UDL) encourage?', 'multiple_choice', '[{"text":"Designing separate programs for children with additional needs","is_correct":false,"explanation":"UDL is about designing programs that are accessible to all children, not creating separate programs."},{"text":"Providing multiple means of engagement, representation, and action so all children can access learning","is_correct":true,"explanation":"UDL encourages educators to provide multiple means of engagement, representation, and action and expression so that all children can access learning."},{"text":"Using only visual learning materials","is_correct":false,"explanation":"UDL promotes multiple means of representation, not just visual materials."},{"text":"Following the same teaching approach for every child","is_correct":false,"explanation":"UDL is specifically about providing multiple pathways to learning, not a uniform approach."}]', 2),

-- Module 22: Cultural Competency Foundations - quiz section b0000087
('c0000064-0000-4000-8000-000000000000', 'b0000087-0000-4000-8000-000000000000', 'What is the first step in developing cultural competency?', 'multiple_choice', '[{"text":"Learning about other cultures","is_correct":false,"explanation":"While learning about other cultures is important, cultural competency begins with self-awareness."},{"text":"Understanding your own cultural identity, values, biases, and assumptions","is_correct":true,"explanation":"Cultural competency begins with self-awareness: understanding your own cultural identity, values, biases, and assumptions is the foundation."},{"text":"Celebrating cultural festivals at the service","is_correct":false,"explanation":"Festival celebrations can be tokenistic. Self-awareness is the foundational first step."},{"text":"Hiring staff from diverse backgrounds","is_correct":false,"explanation":"While diversity in staffing is valuable, individual cultural competency begins with self-awareness."}]', 0),
('c0000065-0000-4000-8000-000000000000', 'b0000087-0000-4000-8000-000000000000', 'What does a "tourist" approach to culture mean, and why should it be avoided?', 'multiple_choice', '[{"text":"Taking children on excursions to cultural sites, which should be encouraged","is_correct":false,"explanation":"The tourist approach is not about excursions. It refers to superficial cultural engagement."},{"text":"Going beyond food, flags, and festivals is unnecessary as these are sufficient","is_correct":false,"explanation":"A tourist approach that only includes food, flags, and festivals is superficial and should be replaced with genuine embedding of cultural perspectives."},{"text":"Reducing culture to food, flags, and festivals rather than genuinely embedding perspectives into everyday practice","is_correct":true,"explanation":"A tourist approach focuses on superficial aspects of culture. Genuine cultural competency means embedding cultural perspectives into everyday interactions, environments, and relationships."},{"text":"Inviting families from different cultures to present at the service","is_correct":false,"explanation":"While family presentations can be valuable, the tourist approach refers to superficial cultural engagement."}]', 1),
('c0000066-0000-4000-8000-000000000000', 'b0000087-0000-4000-8000-000000000000', 'What is anti-bias education?', 'multiple_choice', '[{"text":"Avoiding all discussion of differences with children","is_correct":false,"explanation":"Anti-bias education does not avoid differences but actively engages with them."},{"text":"Teaching children that everyone is exactly the same","is_correct":false,"explanation":"Anti-bias education celebrates diversity rather than denying differences."},{"text":"Actively challenging stereotypes, prejudice, and discrimination, empowering children to recognise unfairness","is_correct":true,"explanation":"Anti-bias education actively challenges stereotypes, prejudice, and discrimination, empowering children to recognise and stand up against unfairness."},{"text":"Only relevant for services with culturally diverse enrolments","is_correct":false,"explanation":"Anti-bias education is important for all services, regardless of the demographic of enrolled children."}]', 2),

-- Module 23: Active Supervision Strategies - quiz section b0000091
('c0000067-0000-4000-8000-000000000000', 'b0000091-0000-4000-8000-000000000000', 'What are the five key elements of active supervision?', 'multiple_choice', '[{"text":"Watching, standing, counting, reporting, resting","is_correct":false,"explanation":"These are not the recognised elements of active supervision."},{"text":"Positioning, scanning, listening, anticipating, and engaging","is_correct":true,"explanation":"The five key elements are positioning, scanning, listening, anticipating, and engaging with children while maintaining awareness."},{"text":"Ratio compliance, documentation, communication, safety checks, and reporting","is_correct":false,"explanation":"These are related to supervision management but not the five specific elements of active supervision practice."},{"text":"Indoor, outdoor, mealtime, sleep time, and transition supervision","is_correct":false,"explanation":"These describe supervision contexts, not the elements of active supervision."}]', 0),
('c0000068-0000-4000-8000-000000000000', 'b0000091-0000-4000-8000-000000000000', 'Which of the following is a high-risk time or activity requiring heightened supervision?', 'multiple_choice', '[{"text":"Circle time with all children seated","is_correct":false,"explanation":"While supervision is always important, circle time with seated children is lower risk than many other activities."},{"text":"Water play, outdoor climbing, and transitions between activities","is_correct":true,"explanation":"Water play, outdoor climbing, sleep and rest, mealtimes, and transitions between activities or spaces are all high-risk times requiring heightened supervision."},{"text":"Reading books in the quiet corner","is_correct":false,"explanation":"Book reading in a quiet area is generally a lower-risk activity."},{"text":"Drawing at a table with an educator present","is_correct":false,"explanation":"Table activities with educator presence are generally lower risk."}]', 1),
('c0000069-0000-4000-8000-000000000000', 'b0000091-0000-4000-8000-000000000000', 'Why should personal devices be stored away during direct supervision of children?', 'multiple_choice', '[{"text":"Children might break the device","is_correct":false,"explanation":"The concern is about supervision quality, not device safety."},{"text":"It is unprofessional to use a phone at work","is_correct":false,"explanation":"While professionalism is important, the primary reason relates to children''s safety."},{"text":"Technology should never distract from supervision duties as it compromises children''s safety","is_correct":true,"explanation":"Personal devices should be stored away because they can distract from supervision duties, compromising children''s safety."},{"text":"Service policy requires it for privacy reasons only","is_correct":false,"explanation":"While privacy is a consideration, the primary reason is that devices distract from supervision duties."}]', 2),

-- Module 24: Quality Improvement Planning (QIP) - quiz section b0000095
('c0000070-0000-4000-8000-000000000000', 'b0000095-0000-4000-8000-000000000000', 'Which regulation requires every approved service to have a Quality Improvement Plan?', 'multiple_choice', '[{"text":"Regulation 31","is_correct":false,"explanation":"Regulation 31 relates to condition of consent, not the QIP."},{"text":"Regulation 55","is_correct":true,"explanation":"Regulation 55 requires every approved education and care service to have a current Quality Improvement Plan."},{"text":"Regulation 73","is_correct":false,"explanation":"Regulation 73 relates to educational programs, not the QIP."},{"text":"Regulation 168","is_correct":false,"explanation":"Regulation 168 relates to policies and procedures, not specifically the QIP."}]', 0),
('c0000071-0000-4000-8000-000000000000', 'b0000095-0000-4000-8000-000000000000', 'Who should be involved in developing the QIP?', 'multiple_choice', '[{"text":"Only the approved provider and nominated supervisor","is_correct":false,"explanation":"Effective QIPs are developed with broad input, not limited to leadership."},{"text":"All educators, families, and where appropriate, children and community members","is_correct":true,"explanation":"Effective QIPs are developed collaboratively with input from all educators, families, and where appropriate, children and community members."},{"text":"Only qualified teachers","is_correct":false,"explanation":"All educators, not just qualified teachers, should contribute to the QIP."},{"text":"An external consultant","is_correct":false,"explanation":"While consultants can assist, the QIP should be developed by the service community including educators, families, and children."}]', 1),
('c0000072-0000-4000-8000-000000000000', 'b0000095-0000-4000-8000-000000000000', 'How often should the QIP be reviewed and updated?', 'multiple_choice', '[{"text":"Only before an assessment and rating visit","is_correct":false,"explanation":"While updating before assessment and rating is essential, the QIP should be a living document reviewed regularly."},{"text":"Annually at the start of each year","is_correct":false,"explanation":"While annual review is the minimum, effective QIPs are updated more frequently."},{"text":"Ideally as an ongoing process at team meetings throughout the year","is_correct":true,"explanation":"The QIP should be reviewed and updated regularly, at minimum before assessment and rating, but ideally as an ongoing process at team meetings throughout the year."},{"text":"Every five years when the service approval is renewed","is_correct":false,"explanation":"Five years is far too infrequent for QIP review. It should be an ongoing, living document."}]', 2),

-- Module 25: ECA Code of Ethics & Professional Standards - quiz section b0000099
('c0000073-0000-4000-8000-000000000000', 'b0000099-0000-4000-8000-000000000000', 'What are the five areas of commitment in the ECA Code of Ethics?', 'multiple_choice', '[{"text":"Safety, learning, health, wellbeing, and development","is_correct":false,"explanation":"These are related to the NQS areas, not the ECA Code of Ethics commitments."},{"text":"Children, families, colleagues, communities and society, and the profession","is_correct":true,"explanation":"The ECA Code of Ethics is organised around commitments to children, families, colleagues, communities and society, and the profession."},{"text":"Curriculum, assessment, environment, relationships, and governance","is_correct":false,"explanation":"These relate to Quality Areas, not the ECA Code of Ethics structure."},{"text":"Respect, integrity, courage, justice, and compassion","is_correct":false,"explanation":"While some of these are values in the Code, they are not the five areas of commitment."}]', 0),
('c0000074-0000-4000-8000-000000000000', 'b0000099-0000-4000-8000-000000000000', 'How does the ECA Code of Ethics help with ethical dilemmas?', 'multiple_choice', '[{"text":"It provides specific answers to every ethical question","is_correct":false,"explanation":"The Code provides a framework for reflection and decision-making, not prescriptive answers."},{"text":"It provides a framework for reflecting on and resolving tensions between competing values","is_correct":true,"explanation":"The Code provides a framework for reflecting on and resolving ethical tensions rather than prescribing specific answers."},{"text":"It tells educators to always follow their supervisor''s instructions","is_correct":false,"explanation":"The Code supports professional judgement and ethical decision-making, not blind compliance."},{"text":"It is not relevant to day-to-day ethical decisions","is_correct":false,"explanation":"The Code is specifically designed to guide everyday professional ethical decisions."}]', 1),
('c0000075-0000-4000-8000-000000000000', 'b0000099-0000-4000-8000-000000000000', 'What professional obligation does the Code place on educators regarding confidentiality?', 'multiple_choice', '[{"text":"All information about children must be shared with all staff","is_correct":false,"explanation":"Information should be shared on a need-to-know basis, not with all staff."},{"text":"Information about children and families should only be shared on a need-to-know basis","is_correct":true,"explanation":"Confidentiality is a professional obligation; information should only be shared on a need-to-know basis in accordance with privacy legislation and policies."},{"text":"Information can be shared freely with other families at the service","is_correct":false,"explanation":"Sharing information about one family with other families would breach confidentiality."},{"text":"Confidentiality only applies to medical information","is_correct":false,"explanation":"Confidentiality applies to all information about children and families, not just medical information."}]', 2),

-- Module 26: Service Induction - quiz section b0000103
('c0000076-0000-4000-8000-000000000000', 'b0000103-0000-4000-8000-000000000000', 'Which of the following should be covered during a service induction?', 'multiple_choice', '[{"text":"Only emergency evacuation procedures","is_correct":false,"explanation":"Induction should be comprehensive, covering much more than just emergency procedures."},{"text":"Philosophy, policies, procedures, routines, emergency procedures, and professional expectations","is_correct":true,"explanation":"A thorough induction covers the service philosophy, organisational structure, policies and procedures, daily routines, emergency procedures, and professional expectations."},{"text":"Only the room routine and educator ratios","is_correct":false,"explanation":"These are important but induction should be much more comprehensive."},{"text":"Only the NQS and EYLF requirements","is_correct":false,"explanation":"While regulatory knowledge is important, induction should cover all aspects of working at the specific service."}]', 0),
('c0000077-0000-4000-8000-000000000000', 'b0000103-0000-4000-8000-000000000000', 'How long should a structured induction period typically last?', 'multiple_choice', '[{"text":"One day only","is_correct":false,"explanation":"One day is insufficient for a thorough induction into an ECEC service."},{"text":"At least four to six weeks","is_correct":true,"explanation":"A buddy or mentor system should support new educators for at least four to six weeks during the induction period."},{"text":"The length of the probation period only","is_correct":false,"explanation":"Induction is about support and orientation, not probation."},{"text":"One week maximum","is_correct":false,"explanation":"One week is too short for new educators to fully integrate into a service."}]', 1),
('c0000078-0000-4000-8000-000000000000', 'b0000103-0000-4000-8000-000000000000', 'What is the benefit of a buddy or mentor system during induction?', 'multiple_choice', '[{"text":"It reduces the workload of the nominated supervisor","is_correct":false,"explanation":"While it may share the support load, the primary benefit is to the new educator."},{"text":"It pairs new educators with experienced team members for ongoing support","is_correct":true,"explanation":"A buddy or mentor system pairs new educators with experienced team members for ongoing support, helping them integrate into the team and understand service practices."},{"text":"It is a regulatory requirement under the National Regulations","is_correct":false,"explanation":"While good practice, buddy systems are not specifically mandated by regulation."},{"text":"It ensures the new educator completes all paperwork on time","is_correct":false,"explanation":"The primary purpose is professional support and orientation, not administrative compliance."}]', 2),

-- Module 27: Critical Reflection for Educators - quiz section b0000107
('c0000079-0000-4000-8000-000000000000', 'b0000107-0000-4000-8000-000000000000', 'What distinguishes critical reflection from simple reflection?', 'multiple_choice', '[{"text":"Critical reflection takes longer to complete","is_correct":false,"explanation":"The distinction is about depth and approach, not time spent."},{"text":"Critical reflection asks why and what if, challenging assumptions and examining the impact of decisions","is_correct":true,"explanation":"Critical reflection involves asking why and what if questions, challenging taken-for-granted assumptions and examining the impact of decisions on children and families."},{"text":"Critical reflection must be done in writing","is_correct":false,"explanation":"Critical reflection can occur through various methods including discussion, not just writing."},{"text":"Critical reflection is only done by managers","is_correct":false,"explanation":"All educators should engage in critical reflection, not just those in management roles."}]', 0),
('c0000080-0000-4000-8000-000000000000', 'b0000107-0000-4000-8000-000000000000', 'Which EYLF V2.0 principle emphasises the importance of reflective practice?', 'multiple_choice', '[{"text":"Secure, respectful and reciprocal relationships","is_correct":false,"explanation":"This is a principle of the EYLF but does not specifically address reflective practice."},{"text":"Ongoing learning and reflective practice","is_correct":true,"explanation":"The EYLF V2.0 identifies ongoing learning and reflective practice as a principle, emphasising that educators who reflect are more responsive and effective."},{"text":"High expectations and equity","is_correct":false,"explanation":"This is a principle but does not specifically focus on reflective practice."},{"text":"Partnerships","is_correct":false,"explanation":"Partnerships is a principle focused on family and community connections, not reflective practice."}]', 1),
('c0000081-0000-4000-8000-000000000000', 'b0000107-0000-4000-8000-000000000000', 'What are common barriers to critical reflection in ECEC teams?', 'multiple_choice', '[{"text":"Having too many qualified staff","is_correct":false,"explanation":"Having qualified staff supports, rather than hinders, critical reflection."},{"text":"Time pressure, fear of judgement, lack of facilitation skills, and comfort with existing routines","is_correct":true,"explanation":"Barriers include time pressure, fear of judgement, lack of facilitation skills, and comfort with existing routines. Leaders must create safe spaces for honest reflection."},{"text":"Access to too many professional development resources","is_correct":false,"explanation":"Access to resources supports reflection rather than creating barriers."},{"text":"Small team sizes","is_correct":false,"explanation":"Small teams can still engage effectively in critical reflection with appropriate facilitation."}]', 2),

-- Module 28: Aboriginal & Torres Strait Islander Perspectives - quiz section b0000111
('c0000082-0000-4000-8000-000000000000', 'b0000111-0000-4000-8000-000000000000', 'What does an Acknowledgement of Country recognise?', 'multiple_choice', '[{"text":"The government of Australia","is_correct":false,"explanation":"An Acknowledgement of Country recognises Traditional Custodians, not the government."},{"text":"The Traditional Custodians of the land on which the service operates","is_correct":true,"explanation":"Acknowledgement of Country recognises the Traditional Custodians of the land and demonstrates respect for Aboriginal and Torres Strait Islander peoples."},{"text":"Australian citizenship","is_correct":false,"explanation":"Acknowledgement of Country is about First Nations sovereignty, not citizenship."},{"text":"The anniversary of Federation","is_correct":false,"explanation":"Acknowledgement of Country relates to First Nations peoples and their connection to Country."}]', 0),
('c0000083-0000-4000-8000-000000000000', 'b0000111-0000-4000-8000-000000000000', 'What is Narragunnawali?', 'multiple_choice', '[{"text":"An Aboriginal language spoken in early childhood settings","is_correct":false,"explanation":"While the word comes from an Aboriginal language, Narragunnawali is a program offered by Reconciliation Australia."},{"text":"A free Reconciliation Action Plan program for early learning services offered by Reconciliation Australia","is_correct":true,"explanation":"Narragunnawali by Reconciliation Australia offers a free RAP program for early learning services to take meaningful action towards reconciliation."},{"text":"A government-mandated cultural assessment tool","is_correct":false,"explanation":"Narragunnawali is a voluntary program, not a mandated assessment tool."},{"text":"A traditional dance taught in ECEC settings","is_correct":false,"explanation":"Narragunnawali is a reconciliation program, not a traditional dance."}]', 1),
('c0000084-0000-4000-8000-000000000000', 'b0000111-0000-4000-8000-000000000000', 'Should services embed Aboriginal and Torres Strait Islander perspectives even if no First Nations children are enrolled?', 'multiple_choice', '[{"text":"No, it is only relevant when Aboriginal children attend","is_correct":false,"explanation":"The EYLF V2.0 expects all services to embed these perspectives regardless of enrolment."},{"text":"Yes, it is a responsibility for every service regardless of the demographic of children enrolled","is_correct":true,"explanation":"This is a responsibility for every educator and service, regardless of the demographic of children enrolled, as it enriches all children''s learning."},{"text":"Only during NAIDOC Week","is_correct":false,"explanation":"Embedding perspectives must go beyond awareness weeks to be part of everyday practice."},{"text":"Only if the service is located on Aboriginal land","is_correct":false,"explanation":"All land in Australia is Aboriginal and/or Torres Strait Islander Country, and all services have this responsibility."}]', 2),

-- Module 29: Trauma-Informed Practice in Early Childhood - quiz section b0000115
('c0000085-0000-4000-8000-000000000000', 'b0000115-0000-4000-8000-000000000000', 'What are the four pillars of trauma-informed care?', 'multiple_choice', '[{"text":"Assessment, treatment, recovery, and follow-up","is_correct":false,"explanation":"These describe a clinical process, not the pillars of trauma-informed care."},{"text":"Safety, trustworthiness, choice, and collaboration","is_correct":true,"explanation":"The four pillars of trauma-informed care are safety (physical and emotional), trustworthiness (consistency and transparency), choice (empowerment and agency), and collaboration."},{"text":"Observe, report, refer, and support","is_correct":false,"explanation":"These are response steps, not the pillars of trauma-informed care."},{"text":"Diagnose, plan, intervene, and evaluate","is_correct":false,"explanation":"This describes a clinical model, not a trauma-informed care framework."}]', 0),
('c0000086-0000-4000-8000-000000000000', 'b0000115-0000-4000-8000-000000000000', 'How should educators understand challenging behaviour in children who have experienced trauma?', 'multiple_choice', '[{"text":"As deliberate defiance that requires consequences","is_correct":false,"explanation":"Trauma responses are survival strategies, not deliberate defiance."},{"text":"As survival strategies, not defiance","is_correct":true,"explanation":"Trauma responses such as hypervigilance, withdrawal, or aggression are survival strategies that helped the child cope, not deliberate misbehaviour."},{"text":"As a sign that the child needs a different educational setting","is_correct":false,"explanation":"Children affected by trauma can be supported within ECEC settings with appropriate approaches."},{"text":"As behaviour that should be ignored until it stops","is_correct":false,"explanation":"Ignoring trauma responses does not address the underlying need and may increase distress."}]', 1),
('c0000087-0000-4000-8000-000000000000', 'b0000115-0000-4000-8000-000000000000', 'What risk do educators face when working with children who have experienced trauma?', 'multiple_choice', '[{"text":"Risk of being blamed for the child''s behaviour","is_correct":false,"explanation":"While this may occur, the specific risk addressed in trauma-informed practice is secondary traumatic stress."},{"text":"Secondary traumatic stress and compassion fatigue","is_correct":true,"explanation":"Secondary traumatic stress and compassion fatigue are real risks for educators working with children who have experienced trauma. Services should provide support and supervision."},{"text":"Risk of legal liability","is_correct":false,"explanation":"Legal liability is not the primary risk associated with working with children affected by trauma."},{"text":"No significant risks if they follow procedures","is_correct":false,"explanation":"Even with good procedures, the emotional demands of supporting traumatised children can affect educator wellbeing."}]', 2),

-- Module 30: Sustained Shared Thinking & Deep Learning - quiz section b0000119
('c0000088-0000-4000-8000-000000000000', 'b0000119-0000-4000-8000-000000000000', 'What research identified sustained shared thinking as a key factor in effective early childhood programs?', 'multiple_choice', '[{"text":"The Heckman Equation","is_correct":false,"explanation":"The Heckman Equation is about the economic return on early childhood investment, not sustained shared thinking."},{"text":"The EPPE (Effective Provision of Pre-School Education) project","is_correct":true,"explanation":"The EPPE project, a major UK longitudinal study, identified sustained shared thinking as a key factor in the most effective early childhood settings."},{"text":"The Reggio Emilia approach","is_correct":false,"explanation":"While Reggio values collaborative thinking, the specific research identification came from the EPPE project."},{"text":"The Australian Early Development Census","is_correct":false,"explanation":"The AEDC measures developmental outcomes but did not identify sustained shared thinking as a concept."}]', 0),
('c0000089-0000-4000-8000-000000000000', 'b0000119-0000-4000-8000-000000000000', 'When is sustained shared thinking most likely to occur?', 'multiple_choice', '[{"text":"During large group, educator-directed activities","is_correct":false,"explanation":"Sustained shared thinking is less common in large group activities and more frequent in small group or one-on-one interactions."},{"text":"In warm, trusting relationships where children feel safe to take intellectual risks","is_correct":true,"explanation":"Sustained shared thinking is most likely to occur in warm, trusting relationships where children feel safe to take intellectual risks, make mistakes, and explore ideas freely."},{"text":"Only during structured learning times","is_correct":false,"explanation":"Sustained shared thinking can happen during any part of the day including routine moments and free play."},{"text":"When children are working independently without adult interaction","is_correct":false,"explanation":"Sustained shared thinking requires interaction between adults and children, not independent work."}]', 1),
('c0000090-0000-4000-8000-000000000000', 'b0000119-0000-4000-8000-000000000000', 'Which of the following is an example of a thinking prompt that supports sustained shared thinking?', 'multiple_choice', '[{"text":"Please sit down and finish your work","is_correct":false,"explanation":"This is a directive that closes thinking rather than extending it."},{"text":"That''s a great painting, well done!","is_correct":false,"explanation":"While positive, this is evaluative praise that does not extend thinking."},{"text":"I wonder why the water runs downhill... what do you think?","is_correct":true,"explanation":"Open-ended wondering prompts like this invite children into deeper thinking and genuine intellectual partnership."},{"text":"Can you tell me what colour this is?","is_correct":false,"explanation":"This is a closed, recall-based question that does not support sustained shared thinking."}]', 2),

-- Module 31: Educational Leadership in Practice - quiz section b0000123
('c0000091-0000-4000-8000-000000000000', 'b0000123-0000-4000-8000-000000000000', 'Which regulation requires every approved service to designate an Educational Leader?', 'multiple_choice', '[{"text":"Regulation 73","is_correct":false,"explanation":"Regulation 73 relates to the educational program, not the Educational Leader designation."},{"text":"Regulation 118","is_correct":true,"explanation":"Regulation 118 requires every approved service to designate a suitably qualified and experienced educator as the Educational Leader."},{"text":"Regulation 168","is_correct":false,"explanation":"Regulation 168 relates to policies and procedures."},{"text":"Regulation 136","is_correct":false,"explanation":"Regulation 136 relates to first aid qualifications, not the Educational Leader."}]', 0),
('c0000092-0000-4000-8000-000000000000', 'b0000123-0000-4000-8000-000000000000', 'What does distributed educational leadership mean?', 'multiple_choice', '[{"text":"The Educational Leader works in a different room each day","is_correct":false,"explanation":"Distributed leadership is about sharing leadership responsibilities, not rotating physical locations."},{"text":"All educators are empowered to take ownership of curriculum decisions and reflect critically on practice","is_correct":true,"explanation":"Distributed leadership means empowering all educators to contribute to curriculum decisions, programming, and critical reflection, not concentrating leadership in one person."},{"text":"Leadership responsibilities are divided equally among all staff","is_correct":false,"explanation":"Distributed leadership is about empowerment and ownership, not equal division of tasks."},{"text":"The Educational Leader delegates all responsibilities to room leaders","is_correct":false,"explanation":"Delegation without empowerment is not distributed leadership."}]', 1),
('c0000093-0000-4000-8000-000000000000', 'b0000123-0000-4000-8000-000000000000', 'How should the Educational Leader be visible in practice?', 'multiple_choice', '[{"text":"By attending every staff meeting","is_correct":false,"explanation":"While meetings are important, being visible in practice means being present in learning environments."},{"text":"By sending weekly emails about curriculum updates","is_correct":false,"explanation":"Email communication is useful but does not constitute being visible in practice."},{"text":"By spending time in rooms observing, modelling, co-teaching, and providing feedback","is_correct":true,"explanation":"The Educational Leader should be visible in practice by spending time in rooms observing, modelling, co-teaching, and providing feedback that builds educator confidence."},{"text":"By displaying their qualifications on the staff noticeboard","is_correct":false,"explanation":"Displaying qualifications is not related to being visible in practice."}]', 2),

-- Module 32: Environmental Sustainability with Children - quiz section b0000127
('c0000094-0000-4000-8000-000000000000', 'b0000127-0000-4000-8000-000000000000', 'What does Element 3.2.3 of the NQS require?', 'multiple_choice', '[{"text":"That the service has a garden maintained by staff only","is_correct":false,"explanation":"Element 3.2.3 is about the service caring for the environment and supporting children to become environmentally responsible, not staff-only gardening."},{"text":"That the service cares for the environment and supports children to become environmentally responsible","is_correct":true,"explanation":"Element 3.2.3 requires that the service cares for the environment and supports children to become environmentally responsible, going beyond recycling."},{"text":"That the service uses only recycled materials","is_correct":false,"explanation":"While using recycled materials is one strategy, Element 3.2.3 encompasses a broader approach to environmental responsibility."},{"text":"That the outdoor area includes natural elements","is_correct":false,"explanation":"Natural elements relate more to Element 3.2.1 about outdoor spaces. Element 3.2.3 specifically addresses environmental responsibility."}]', 0),
('c0000095-0000-4000-8000-000000000000', 'b0000127-0000-4000-8000-000000000000', 'How can children be active participants in sustainability practices?', 'multiple_choice', '[{"text":"By watching educators recycle","is_correct":false,"explanation":"Watching is passive. Active participation involves children in decision-making and hands-on practices."},{"text":"By being involved in decisions about reducing waste, conserving water, caring for plants, and recycling","is_correct":true,"explanation":"Involving children in decisions about sustainability practices builds agency and environmental awareness."},{"text":"By attending presentations about climate change","is_correct":false,"explanation":"Presentations may not be developmentally appropriate and do not constitute active participation."},{"text":"By completing worksheets about the environment","is_correct":false,"explanation":"Worksheets are not aligned with active, play-based learning approaches to sustainability."}]', 1),
('c0000096-0000-4000-8000-000000000000', 'b0000127-0000-4000-8000-000000000000', 'How do Aboriginal and Torres Strait Islander perspectives relate to sustainability?', 'multiple_choice', '[{"text":"They are not relevant to sustainability education","is_correct":false,"explanation":"Aboriginal and Torres Strait Islander perspectives are deeply relevant to sustainability and connection to Country."},{"text":"They provide a deep framework for understanding sustainability, connection to land, and intergenerational responsibility","is_correct":true,"explanation":"Aboriginal and Torres Strait Islander perspectives on caring for Country provide a deep and respectful framework for understanding sustainability and intergenerational responsibility."},{"text":"They only relate to traditional land management practices","is_correct":false,"explanation":"While land management is included, Indigenous perspectives on sustainability encompass a much broader worldview."},{"text":"They should only be taught by Aboriginal educators","is_correct":false,"explanation":"While Aboriginal educators bring invaluable expertise, all educators can respectfully incorporate Indigenous perspectives on sustainability."}]', 2),

-- Module 33: Supporting Transitions - quiz section b0000131
('c0000097-0000-4000-8000-000000000000', 'b0000131-0000-4000-8000-000000000000', 'Is transition to school a single event or an ongoing process?', 'multiple_choice', '[{"text":"A single event on the first day of school","is_correct":false,"explanation":"Transition to school is a process that begins well before and continues after the first day."},{"text":"An ongoing process that begins before and continues into the early weeks and months of school","is_correct":true,"explanation":"Transition to school is a process, not an event, requiring collaboration between families, ECEC services, and schools over time."},{"text":"A one-week orientation program at the school","is_correct":false,"explanation":"While orientation visits are part of transition, the process extends well beyond a single week."},{"text":"An assessment conducted by the school to determine readiness","is_correct":false,"explanation":"Transition is a support process, not an assessment of readiness."}]', 0),
('c0000098-0000-4000-8000-000000000000', 'b0000131-0000-4000-8000-000000000000', 'How should room-to-room transitions within a service be managed?', 'multiple_choice', '[{"text":"Moving all children on the same date at the start of the year","is_correct":false,"explanation":"Transitions should be gradual and child-paced, not done in bulk on a set date."},{"text":"Gradually and child-paced, with visits, introductions, and information sharing","is_correct":true,"explanation":"Room-to-room transitions should be gradual and child-paced, with visits to the new room, introduction to new educators, and sharing of information."},{"text":"Without any prior visits to avoid confusion","is_correct":false,"explanation":"Prior visits help children feel comfortable and prepared for the transition."},{"text":"By sending a letter to parents on the day of the move","is_correct":false,"explanation":"Families should be involved in transition planning well before the actual move, not notified on the day."}]', 1),
('c0000099-0000-4000-8000-000000000000', 'b0000131-0000-4000-8000-000000000000', 'What supports continuity of learning during transitions?', 'multiple_choice', '[{"text":"Starting fresh with no information about the child","is_correct":false,"explanation":"Starting without information loses valuable knowledge about the child''s learning journey."},{"text":"Documenting and sharing transition statements or summaries with the receiving educator or teacher","is_correct":true,"explanation":"Transition statements support continuity by ensuring the receiving educator has a picture of the child''s strengths, interests, and learning journey."},{"text":"Repeating assessments in the new setting","is_correct":false,"explanation":"Repeating assessments is unnecessary if information is shared and can delay responsive programming."},{"text":"Requiring the child to demonstrate skills in the new room","is_correct":false,"explanation":"Transitions should be supportive, not assessment-focused."}]', 2),

-- Module 34: Engaging Families in Programming & Assessment - quiz section b0000135
('c0000100-0000-4000-8000-000000000000', 'b0000135-0000-4000-8000-000000000000', 'What does genuine family engagement in programming look like?', 'multiple_choice', '[{"text":"Sending home a newsletter about completed activities","is_correct":false,"explanation":"Newsletters inform families but do not constitute genuine engagement in programming decisions."},{"text":"Family input genuinely influencing the program with the link made explicit","is_correct":true,"explanation":"When a family shares an interest or experience, it should be visible in curriculum planning with the link made explicit for families."},{"text":"Inviting families to attend concerts and events","is_correct":false,"explanation":"Events are one form of involvement but do not represent genuine engagement in programming and assessment."},{"text":"Asking families to volunteer in the classroom","is_correct":false,"explanation":"Volunteering is valuable but does not necessarily involve families in programming decisions."}]', 0),
('c0000101-0000-4000-8000-000000000000', 'b0000135-0000-4000-8000-000000000000', 'Why should services offer multiple ways for families to engage?', 'multiple_choice', '[{"text":"To meet regulatory quotas for family participation","is_correct":false,"explanation":"There are no regulatory quotas for family participation."},{"text":"Because not all families can attend meetings; options might include digital, surveys, phone calls, and informal conversations","is_correct":true,"explanation":"Multiple engagement options recognise that families have different availability and preferences, and ensure all families can participate."},{"text":"To make it easier for educators to manage communication","is_correct":false,"explanation":"Multiple options may require more effort from educators but ensure equitable access for families."},{"text":"Because it looks good during assessment and rating","is_correct":false,"explanation":"While it supports quality assessment, the purpose is genuine inclusion of all families."}]', 1),
('c0000102-0000-4000-8000-000000000000', 'b0000135-0000-4000-8000-000000000000', 'How should assessment of children''s learning incorporate family perspectives?', 'multiple_choice', '[{"text":"Families should complete formal assessment forms","is_correct":false,"explanation":"Formal forms may be a barrier. Family perspectives can be gathered through many methods."},{"text":"Family perspectives are not needed for professional assessment","is_correct":false,"explanation":"Families know their children best and provide essential insights that educators may not observe at the service."},{"text":"Families can provide insights into development, interests, and abilities that educators may not observe at the service","is_correct":true,"explanation":"Families know their children best and can provide insights into development, interests, and abilities that complement educator observations."},{"text":"Families should only be consulted if there are concerns about a child''s development","is_correct":false,"explanation":"Family input should be ongoing for all children, not limited to times of concern."}]', 2),

-- Module 35: Community Partnerships & Referral Pathways - quiz section b0000139
('c0000103-0000-4000-8000-000000000000', 'b0000139-0000-4000-8000-000000000000', 'What types of organisations might a service partner with?', 'multiple_choice', '[{"text":"Only government agencies","is_correct":false,"explanation":"Community partnerships can include a wide range of organisations, not just government agencies."},{"text":"Local schools, libraries, health services, cultural organisations, environmental groups, and community centres","is_correct":true,"explanation":"Community partnerships may include relationships with schools, libraries, health services, cultural organisations, environmental groups, businesses, and community centres."},{"text":"Only other early childhood services","is_correct":false,"explanation":"While partnerships with other ECEC services are valuable, the range of potential partners is much broader."},{"text":"Only organisations that provide funding","is_correct":false,"explanation":"Community partnerships are about enriching the program and supporting families, not just funding."}]', 0),
('c0000104-0000-4000-8000-000000000000', 'b0000139-0000-4000-8000-000000000000', 'What role do educators play in connecting families with support services?', 'multiple_choice', '[{"text":"They should diagnose issues and provide advice","is_correct":false,"explanation":"Educators should not diagnose. Their role is to identify when support may be needed and provide information about available services."},{"text":"They should identify when families may benefit from support and sensitively provide information about available services","is_correct":true,"explanation":"Educators play a key role in identifying when families may benefit from additional support and sensitively raising concerns and providing information."},{"text":"They should not get involved in family issues","is_correct":false,"explanation":"Supporting families to access services is part of the educator''s professional role under QA6."},{"text":"They should contact services directly on behalf of families without consent","is_correct":false,"explanation":"Referrals should be made with family knowledge and consent, respecting their autonomy."}]', 1),
('c0000105-0000-4000-8000-000000000000', 'b0000139-0000-4000-8000-000000000000', 'What is the benefit of maintaining an up-to-date community resources directory?', 'multiple_choice', '[{"text":"It satisfies a specific regulatory requirement","is_correct":false,"explanation":"While it supports quality practice, there is no specific regulation requiring a community directory."},{"text":"It ensures educators can quickly access information about local services, eligibility, and referral processes","is_correct":true,"explanation":"An up-to-date directory ensures educators can quickly and accurately connect families with the services they need."},{"text":"It provides content for newsletters to families","is_correct":false,"explanation":"While directory information can be shared, the primary purpose is to support timely and accurate referrals."},{"text":"It is only needed for accreditation purposes","is_correct":false,"explanation":"A community directory serves ongoing practical purposes, not just accreditation."}]', 2),

-- Module 36: Mentoring & Coaching Skills for Leaders - quiz section b0000143
('c0000106-0000-4000-8000-000000000000', 'b0000143-0000-4000-8000-000000000000', 'What is the difference between mentoring and coaching?', 'multiple_choice', '[{"text":"They are exactly the same thing","is_correct":false,"explanation":"Mentoring and coaching are distinct but complementary approaches."},{"text":"Mentoring is longer-term and broader, while coaching is more focused and goal-oriented","is_correct":true,"explanation":"Mentoring is typically a longer-term relationship focused on overall professional development, while coaching is usually more focused and goal-oriented."},{"text":"Mentoring is for new staff and coaching is for experienced staff only","is_correct":false,"explanation":"Both approaches can be used with staff at any career stage."},{"text":"Coaching involves telling people what to do, while mentoring is more collaborative","is_correct":false,"explanation":"Both mentoring and coaching should be collaborative rather than directive."}]', 0),
('c0000107-0000-4000-8000-000000000000', 'b0000143-0000-4000-8000-000000000000', 'What does the GROW model stand for?', 'multiple_choice', '[{"text":"Goals, Resources, Outcomes, Work","is_correct":false,"explanation":"The R in GROW stands for Reality, not Resources."},{"text":"Goal, Reality, Options, Will","is_correct":true,"explanation":"The GROW model structures coaching conversations: Goal (what do you want to achieve?), Reality (where are you now?), Options (what could you do?), Will (what will you do?)."},{"text":"Guide, Reflect, Observe, Write","is_correct":false,"explanation":"This is not the GROW model framework."},{"text":"Gather, Review, Organise, Watch","is_correct":false,"explanation":"This is not the GROW model framework."}]', 1),
('c0000108-0000-4000-8000-000000000000', 'b0000143-0000-4000-8000-000000000000', 'What is more effective than telling people what to do in coaching?', 'multiple_choice', '[{"text":"Giving written instructions","is_correct":false,"explanation":"Written instructions are still directive. Guided inquiry is more effective for lasting behaviour change."},{"text":"Demonstrating and expecting them to copy","is_correct":false,"explanation":"While modelling can be useful, guided inquiry develops deeper understanding and ownership."},{"text":"Helping them discover answers through guided inquiry using active listening, open-ended questions, and reflective feedback","is_correct":true,"explanation":"Effective coaching uses active listening, open-ended questioning, and reflective feedback to help educators discover their own answers through guided inquiry."},{"text":"Sending them to external training courses","is_correct":false,"explanation":"External training is one tool but does not replace the personalised support of coaching conversations."}]', 2),

-- Module 37: Risk-Benefit Assessment in Play Environments - quiz section b0000147
('c0000109-0000-4000-8000-000000000000', 'b0000147-0000-4000-8000-000000000000', 'What is the difference between a risk and a hazard?', 'multiple_choice', '[{"text":"They are the same thing","is_correct":false,"explanation":"Risk and hazard are distinct concepts in risk-benefit assessment."},{"text":"A risk is something a child can assess and choose to engage with; a hazard is a danger the child cannot foresee","is_correct":true,"explanation":"A risk is something a child can assess and choose to engage with, while a hazard is a danger that the child cannot reasonably be expected to foresee or manage."},{"text":"A hazard is less dangerous than a risk","is_correct":false,"explanation":"A hazard is actually a more serious concern because the child cannot foresee or manage it."},{"text":"Risks only exist outdoors, hazards only exist indoors","is_correct":false,"explanation":"Both risks and hazards can exist in any environment."}]', 0),
('c0000110-0000-4000-8000-000000000000', 'b0000147-0000-4000-8000-000000000000', 'What developmental purposes does risky play serve?', 'multiple_choice', '[{"text":"It has no developmental benefit and should be avoided","is_correct":false,"explanation":"Research shows risky play serves important developmental purposes."},{"text":"It builds physical skills, risk assessment ability, resilience, self-confidence, and executive function","is_correct":true,"explanation":"Risky play builds physical skills, develops risk assessment ability, fosters resilience, promotes self-confidence, and supports executive function development."},{"text":"It only develops physical strength","is_correct":false,"explanation":"The benefits of risky play extend well beyond physical development to include cognitive and social-emotional skills."},{"text":"It teaches children to follow safety rules","is_correct":false,"explanation":"Risky play develops internal risk assessment skills rather than external rule-following."}]', 1),
('c0000111-0000-4000-8000-000000000000', 'b0000147-0000-4000-8000-000000000000', 'How do overly cautious educator attitudes affect children''s play?', 'multiple_choice', '[{"text":"They keep children completely safe from all harm","is_correct":false,"explanation":"Being overly cautious can deprive children of valuable learning without eliminating all risk."},{"text":"They can deprive children of valuable learning opportunities and challenge","is_correct":true,"explanation":"Overly cautious responses can deprive children of valuable learning opportunities, while negligent approaches compromise safety. Balance is key."},{"text":"They have no impact on children''s experiences","is_correct":false,"explanation":"Educator attitudes significantly influence the range and quality of play experiences available to children."},{"text":"They are always the safest approach","is_correct":false,"explanation":"Being overly cautious is not the same as being safe; it can actually hinder children''s development of risk competence."}]', 2),

-- Module 38: Children's Rights, Agency & Participation - quiz section b0000151
('c0000112-0000-4000-8000-000000000000', 'b0000151-0000-4000-8000-000000000000', 'What does Article 12 of the UNCRC state?', 'multiple_choice', '[{"text":"Children have the right to free education","is_correct":false,"explanation":"The right to education is addressed in other articles. Article 12 is about children''s right to express their views."},{"text":"Children have the right to express their views freely in all matters affecting them","is_correct":true,"explanation":"Article 12 states that children have the right to express their views freely in all matters affecting them, with due weight given according to age and maturity."},{"text":"Children have the right to play","is_correct":false,"explanation":"The right to play is covered in Article 31, not Article 12."},{"text":"Children have the right to a safe environment","is_correct":false,"explanation":"Safety is addressed in other articles. Article 12 specifically addresses children''s right to be heard."}]', 0),
('c0000113-0000-4000-8000-000000000000', 'b0000151-0000-4000-8000-000000000000', 'What does genuine participation for children mean?', 'multiple_choice', '[{"text":"Giving children a choice between two educator-selected options","is_correct":false,"explanation":"Offering two pre-selected options is limited choice, not genuine participation in decision-making."},{"text":"Genuinely including children in decision-making about their learning, environment, routines, and rules","is_correct":true,"explanation":"Participation goes beyond limited choices to genuinely including children in decision-making about matters that affect them."},{"text":"Letting children do whatever they want","is_correct":false,"explanation":"Participation does not mean no boundaries. It means children''s views are sought and considered within appropriate limits."},{"text":"Asking children to vote on activities once a week","is_correct":false,"explanation":"Weekly voting is one strategy but genuine participation should be embedded in daily practice."}]', 1),
('c0000114-0000-4000-8000-000000000000', 'b0000151-0000-4000-8000-000000000000', 'How can educators support children''s agency in the learning environment?', 'multiple_choice', '[{"text":"By planning every activity in advance with no room for deviation","is_correct":false,"explanation":"Rigid pre-planning limits children''s agency. Responsive planning supports it."},{"text":"By providing open-ended materials, flexible routines, child-led play, and environments children can modify","is_correct":true,"explanation":"Supporting agency involves providing open-ended materials, flexible routines, child-led play, opportunities for self-help, and environments that children can modify."},{"text":"By asking children to choose from a set menu of activities","is_correct":false,"explanation":"A set menu limits agency. Open-ended materials and flexible environments offer more genuine choice."},{"text":"By allowing children to skip routines they dislike","is_correct":false,"explanation":"Agency is about meaningful participation in decisions, not simply opting out of routines."}]', 2),

-- Module 39: Leading Change & Continuous Improvement - quiz section b0000155
('c0000115-0000-4000-8000-000000000000', 'b0000155-0000-4000-8000-000000000000', 'What is the first step in leading successful change according to Kotter''s model?', 'multiple_choice', '[{"text":"Form a guiding coalition","is_correct":false,"explanation":"Forming a guiding coalition is the second step. The first step is creating a sense of urgency."},{"text":"Create a sense of urgency","is_correct":true,"explanation":"Kotter''s eight-step model begins with creating urgency: helping the team understand why the change is necessary and important."},{"text":"Develop a vision for change","is_correct":false,"explanation":"Developing a vision is the third step, after creating urgency and forming a coalition."},{"text":"Generate short-term wins","is_correct":false,"explanation":"Generating short-term wins comes later in the process, after the vision has been communicated and action empowered."}]', 0),
('c0000116-0000-4000-8000-000000000000', 'b0000155-0000-4000-8000-000000000000', 'Why is resistance to change considered natural?', 'multiple_choice', '[{"text":"Because people are generally lazy and do not want to work harder","is_correct":false,"explanation":"Resistance is not about laziness. It comes from valid concerns such as fear, loss of competence, or past experiences."},{"text":"Because of fear of the unknown, loss of competence, increased workload, or past negative experiences","is_correct":true,"explanation":"Common sources of resistance include fear of the unknown, loss of competence, increased workload, disagreement with direction, or past negative experiences with change."},{"text":"Because educators are not interested in professional growth","is_correct":false,"explanation":"Most educators are interested in growth but may resist change for valid reasons."},{"text":"Resistance is not natural and should be treated as insubordination","is_correct":false,"explanation":"Resistance is a natural human response to change and should be understood and addressed, not punished."}]', 1),
('c0000117-0000-4000-8000-000000000000', 'b0000155-0000-4000-8000-000000000000', 'Why are short-term wins important in a change process?', 'multiple_choice', '[{"text":"They allow leaders to declare the change complete early","is_correct":false,"explanation":"Short-term wins are milestones, not the end of the change process. Premature declaration of success undermines sustainability."},{"text":"They demonstrate that the change is worthwhile and build confidence for further improvement","is_correct":true,"explanation":"Short-term wins maintain momentum by demonstrating value and building confidence and commitment for continued change."},{"text":"They are required by the regulatory authority","is_correct":false,"explanation":"Short-term wins are a change management strategy, not a regulatory requirement."},{"text":"They replace the need for a long-term plan","is_correct":false,"explanation":"Short-term wins complement, not replace, long-term planning and vision."}]', 2),

-- Module 40: Philosophy Development & Review - quiz section b0000159
('c0000118-0000-4000-8000-000000000000', 'b0000159-0000-4000-8000-000000000000', 'Which NQS element requires that a statement of philosophy guides all aspects of the service?', 'multiple_choice', '[{"text":"Element 1.1.1","is_correct":false,"explanation":"Element 1.1.1 relates to the approved learning framework guiding the program, not the philosophy."},{"text":"Element 7.1.1","is_correct":true,"explanation":"Element 7.1.1 requires that a statement of philosophy guides all aspects of the service''s operations."},{"text":"Element 7.2.1","is_correct":false,"explanation":"Element 7.2.1 relates to continuous improvement, not the philosophy statement."},{"text":"Element 4.1.1","is_correct":false,"explanation":"Element 4.1.1 relates to organisation of educators, not the philosophy."}]', 0),
('c0000119-0000-4000-8000-000000000000', 'b0000159-0000-4000-8000-000000000000', 'Who should be involved in developing the service philosophy?', 'multiple_choice', '[{"text":"Only the approved provider and nominated supervisor","is_correct":false,"explanation":"Philosophy development should be collaborative, not limited to leadership."},{"text":"Educators, families, children where appropriate, and community members","is_correct":true,"explanation":"Philosophy development should include the perspectives of educators, families, children where appropriate, and community members, ensuring shared ownership."},{"text":"Only qualified teachers","is_correct":false,"explanation":"All team members and stakeholders should contribute to philosophy development."},{"text":"An external education consultant","is_correct":false,"explanation":"While consultants can facilitate, the philosophy should reflect the service community''s shared values."}]', 1),
('c0000120-0000-4000-8000-000000000000', 'b0000159-0000-4000-8000-000000000000', 'How often should the service philosophy be reviewed?', 'multiple_choice', '[{"text":"Only when there is a change of management","is_correct":false,"explanation":"Philosophy review should be regular, not triggered only by management changes."},{"text":"Every five years","is_correct":false,"explanation":"Five years is too infrequent. The philosophy should remain current and responsive."},{"text":"At least annually","is_correct":true,"explanation":"Regular review, at least annually, ensures the philosophy remains current and responsive to the evolving context of the service."},{"text":"It should never change once established","is_correct":false,"explanation":"A philosophy is a living document that should evolve as the service community changes and grows."}]', 2),

-- Module 41: Performance Review & PDP Development - quiz section b0000163
('c0000121-0000-4000-8000-000000000000', 'b0000163-0000-4000-8000-000000000000', 'How often should performance reviews be conducted?', 'multiple_choice', '[{"text":"Only when there is a performance concern","is_correct":false,"explanation":"Performance reviews should be proactive and regular, not just reactive to concerns."},{"text":"At least annually with quarterly check-ins","is_correct":true,"explanation":"Performance reviews should be conducted at least annually, with regular check-ins at least quarterly to monitor PDP progress and provide support."},{"text":"Every two years","is_correct":false,"explanation":"Two years is too infrequent for effective performance management and professional growth."},{"text":"Monthly formal reviews are required","is_correct":false,"explanation":"Monthly formal reviews are not typically necessary; annual reviews with quarterly check-ins are effective."}]', 0),
('c0000122-0000-4000-8000-000000000000', 'b0000163-0000-4000-8000-000000000000', 'What does SMART stand for in goal setting?', 'multiple_choice', '[{"text":"Simple, Meaningful, Achievable, Relevant, Timely","is_correct":false,"explanation":"The S in SMART stands for Specific, and the T stands for Time-bound."},{"text":"Specific, Measurable, Achievable, Relevant, Time-bound","is_correct":true,"explanation":"SMART goals are Specific, Measurable, Achievable, Relevant, and Time-bound, providing a framework for meaningful, trackable goals."},{"text":"Strategic, Monitored, Assessed, Reviewed, Tracked","is_correct":false,"explanation":"This is not the SMART goal framework."},{"text":"Suitable, Managed, Appropriate, Realistic, Targeted","is_correct":false,"explanation":"This is not the correct SMART framework."}]', 1),
('c0000123-0000-4000-8000-000000000000', 'b0000163-0000-4000-8000-000000000000', 'What should a PDP include besides formal training opportunities?', 'multiple_choice', '[{"text":"Only external workshop attendance","is_correct":false,"explanation":"PDPs should include a range of learning strategies beyond formal workshops."},{"text":"A range of strategies including mentoring, peer observation, reading, online learning, action research, and collaborative projects","is_correct":true,"explanation":"PDPs should identify diverse professional learning strategies including mentoring, peer observation, reading, online learning, action research, and collaborative projects."},{"text":"Only activities that earn formal qualifications","is_correct":false,"explanation":"Professional growth comes from many sources, not just qualification-bearing activities."},{"text":"Nothing else; formal training is sufficient","is_correct":false,"explanation":"Effective professional development uses multiple strategies, not just formal training."}]', 2);


