INSERT INTO lms_pathways (id, title, description, related_qa, tier, estimated_hours, status) VALUES
('d0000001-0000-4000-8000-000000000000', 'New Educator Induction Pathway', 'Essential modules for new educators joining the team, covering workplace safety, child protection, service orientation, and regulatory foundations.', '{2,4,7}', 'mandatory', 3.5, 'published'),
('d0000002-0000-4000-8000-000000000000', 'Annual Mandatory Compliance', 'Yearly refresher modules covering CPR, anaphylaxis, asthma management, child protection, safe sleep, and emergency procedures to maintain compliance.', '{2}', 'mandatory', 2.5, 'published'),
('d0000003-0000-4000-8000-000000000000', 'Meeting QA1: Educational Program', 'Focused pathway on educational program and practice, covering the EYLF, planning cycle, intentional teaching, documentation, and cultural competency.', '{1}', 'core', 3.0, 'published'),
('d0000004-0000-4000-8000-000000000000', 'Meeting QA2: Health & Safety', 'Comprehensive health and safety pathway covering first aid, CPR, anaphylaxis, asthma management, safe sleep, emergency procedures, and active supervision.', '{2}', 'core', 3.5, 'published'),
('d0000005-0000-4000-8000-000000000000', 'Exceeding NQS Preparation', 'Advanced professional learning pathway preparing educators for Exceeding-level practice through critical reflection, Indigenous perspectives, deep learning, family engagement, and continuous improvement.', '{1,5,6,7}', 'advanced', 2.5, 'published');


